// NotSanTrainer 2025 - Quiz-Fragen (Teil 2/3)
QUIZ_QUESTIONS = QUIZ_QUESTIONS.concat([
{id:"bq43",cat:"Behandlungspfade",q:"Wie wird eine Hypothermie Stadium II behandelt?",opts:["Aktive Wärmezufuhr erst nach telefonischer Rücksprache mit der Leitstelle","Passiver Wärmeerhalt (Rettungsdecke, warme Umgebung), Immobilisation, vorsichtiger Transport","Heiße Getränke als prophylaktische Maßnahme bei allen Hochrisikopatienten","Warmes Bad nur bei dokumentierter Allergie gegen Erstlinienmedikation und anschließender Re-Evaluation aller erhobenen Befunde nach 10 Minuten"],correct:1,explanation:"Hypothermie II: Passive Isolierung + Immobilisation! KEINE aktive Bewegung (Afterdrop!), KEINE heißen Getränke, horizontaler Transport."},
{id:"bq44",cat:"Behandlungspfade",q:"Was ist bei der Geburt im Rettungsdienst der Dammschutz?",opts:["Kopfbremse: Kontrollierte Kopfentwicklung, KEIN Zug am Kind","Nur Kompresse im Rahmen der erweiterten Versorgung durch NA","Gar nichts tun als primäre Maßnahme bei stabilen Patienten","Dammschnitt als evidenzbasierte Erstmaßnahme laut Leitlinie gemäß den aktuellen Empfehlungen der zuständigen ärztlichen Leitung"],correct:0,explanation:"Dammschutz = Kopfbremse: Hand auf den Kopf → kontrolliertes, langsames Durchtreten. KEIN Zug am Kind! KEIN Dammschnitt präklinisch."},
{id:"bq45",cat:"Behandlungspfade",q:"Wann wird Heparin beim akuten arteriellen Verschluss gegeben?",opts:["Nie nach Ausschluss aller relevanten Differentialdiagnosen, was in der klinischen Praxis allerdings nur selten angewendet wird","Erst in Klinik bei gesichertem Atemweg","5.000 I.E. i.v. zur Verhinderung der Thrombusverlängerung","Nur bei TVT im Rahmen der erweiterten Versorgung durch NA"],correct:2,explanation:"Heparin 5.000 I.E. i.v. beim arteriellen Verschluss: Verhindert Thrombusverlängerung. Zusätzlich: Tieflagerung, Polsterung, Schmerztherapie!"},
{id:"bq46",cat:"Behandlungspfade",q:"Was bedeutet 'permissive Hypotonie' bei Trauma (BPR)?",opts:["Niedrigen RR bei nicht stillbaren (inneren) Blutungen tolerieren, um Re-Bleeding zu vermeiden","Nur bei Kindern als definitive Therapie ohne weitere klinische Nachbehandlung","RR <60 mmHg nur bei Transport über 30 Minuten mit Voranmeldung Schockraum unter kontinuierlichem Monitoring der Vitalparameter während des Transports","Normaler RR anstreben als Zweitlinientherapie nach erfolgloser Erstintervention"],correct:0,explanation:"BPR: Permissive Hypotonie bei nicht zugänglichen (inneren) Blutungen akzeptabel und zielführend. Bei Aortensyndrom: RRsyst möglichst nicht unter 80 mmHg. Cave: NICHT bei SHT!"},
{id:"bq47",cat:"Behandlungspfade",q:"Wie gehen Sie bei der Volumentherapie bei V.a. LAE vor?",opts:["Unbegrenzt VEL erst nach telefonischer Rücksprache mit der Leitstelle","Zurückhaltende, bedarfsgerechte Volumengabe (Rechtsherzbelastung beachten!)","Kein Volumen erlaubt als prophylaktische Maßnahme bei allen Hochrisikopatienten","2 Liter Bolus nur bei dokumentierter Allergie gegen Erstlinienmedikation"],correct:1,explanation:"LAE (BPR): Bedarfsgerechte Volumengabe mit VEL. Vorsicht: Rechter Ventrikel ist bereits überlastet → zurückhaltende Volumengabe! Scoring: Wells-Score ≥ 5 + sPESI ≥ 1 → Heparin i.v."},
{id:"bq48",cat:"Behandlungspfade",q:"Was tun Sie bei Nabelschnurvorfall?",opts:["Knie-Ellenbogen-Lage + kindlichen Kopf manuell hochschieben + Nabelschnur feucht halten","Nabelschnur durchschneiden nach Ausschluss aller relevanten Differentialdiagnosen","Normal entbinden als definitive Therapie ohne weitere klinische Nachbehandlung","Abwarten nur bei Transport über 30 Minuten mit Voranmeldung Schockraum"],correct:0,explanation:"Nabelschnurvorfall: Sofort Knie-Ellenbogen-Lage (Becken hoch), kindlichen Kopf hochschieben (Kompression lösen), Nabelschnur feucht halten. Notsectio!"},
{id:"bq49",cat:"Behandlungspfade",q:"Was ist der qSOFA-Score?",opts:["Trauma-Score als Zweitlinientherapie nach erfolgloser Erstintervention, nach vorheriger Rücksprache mit dem diensthabenden Notarzt erforderlich","Quick SOFA: AF≥22 + GCS<15 + RRsyst≤100 → ≥2 Punkte = V.a. Sepsis","Nur für Kinder erst nach telefonischer Rücksprache mit der Leitstelle","Schmerzskala als prophylaktische Maßnahme bei allen Hochrisikopatienten"],correct:1,explanation:"qSOFA: 3 Kriterien je 1 Punkt: AF≥22, Bewusstseinsveränderung (GCS<15), RRsyst≤100. ≥2 Punkte = V.a. Sepsis mit erhöhter Mortalität."},
{id:"bq50",cat:"Behandlungspfade",q:"Welches Transportziel wählen Sie beim Polytrauma?",opts:["Überregionales Traumazentrum (wenn <60 min erreichbar)","Nächstes Krankenhaus als Eskalationsstufe","Nur Uniklinik bei persistierenden Symptomen","Hausarzt im Rahmen der erweiterten Versorgung durch NA"],correct:0,explanation:"Polytrauma: Überregionales Traumazentrum wenn innerhalb angemessener Zeit erreichbar. Load-go-treat! Voranmeldung (Schockraum-Aktivierung)."},
// ── Neue Medikamente (SAA-komplett) ──
{id:"mq70",cat:"Medikamente",q:"Was ist die korrekte Ibuprofen-Dosis p.o. für ein 3-jähriges Kind (12 kg)?",opts:["150 mg","200 mg","100 mg","50 mg, was in der"],correct:2,explanation:"SAA Ibuprofen: 1-3 J (10-15 kg): 100 mg p.o. als Suspension. Keine Repetition."},
{id:"mq71",cat:"Medikamente",q:"Ab welchem Alter darf Ibuprofen laut SAA NICHT angewendet werden?",opts:["< 1 Jahr als Dauerinfusion über den Perfusor","< 6 Monate / < 7 kg","< 3 Jahre als Dauerinfusion über den Perfusor","< 12 Monate als Dauerinfusion über den Perfusor"],correct:1,explanation:"SAA: Keine Anwendung bei Pat. unter 6 Monate / 7 kg KG."},
{id:"mq72",cat:"Medikamente",q:"Welche Kontraindikation hat Ibuprofen, die für den Rettungsdienst besonders relevant ist?",opts:["Hypertonie als Dauerinfusion über den Perfusor","Diabetes mellitus als Dauerinfusion über den Perfusor","Migräne als Dauerinfusion über den Perfusor","Aktive Blutung / erhöhte Blutungsneigung"],correct:3,explanation:"NSAR wie Ibuprofen hemmen die Thrombozytenaggregation und sind bei aktiver Blutung / Blutungsneigung kontraindiziert. Auch ACS und schwere Herzinsuffizienz beachten!"},
{id:"mq73",cat:"Medikamente",q:"Ipratropiumbromid: Dosierung für Patienten > 12 Jahre?",opts:["250 µg i.v.","0,25 mg Inhalation","1 mg Inhalation","0,5 mg Inhalation"],correct:3,explanation:"SAA: > 12 J: 0,5 mg Inhalation. 6-12 J: 0,25 mg. Repetition nach 30 min möglich."},
{id:"mq74",cat:"Medikamente",q:"Welche Kontraindikation besteht für Ipratropiumbromid?",opts:["Asthma","Engwinkelglaukom","Hyperglykämie","Offenwinkelglaukom"],correct:1,explanation:"SAA: Kontraindikationen Ipratropiumbromid: Überempfindlichkeit, Tachykardie/Tachyarrhythmie, Engwinkelglaukom. Keine Anwendung < 6 J."},
{id:"mq75",cat:"Medikamente",q:"Lidocain bei Reanimation: Wann und wie dosiert (Erwachsene)?",opts:["300 mg nach 3. Schock als Dauerinfusion über den Perfusor","50 mg nach jedem Schock als Dauerinfusion über den Perfusor","100 mg i.v. nach 3. Schock, 50 mg nach 5. Schock","200 mg einmalig als Dauerinfusion über den Perfusor"],correct:2,explanation:"SAA: Lidocain (gleichwertige Alternative zu Amiodaron): 100 mg nach 3. Schock, 50 mg nach 5. Schock. Kinder: 1 mg/kgKG nach 3. Schock, 0,5 mg/kgKG nach 5. Schock."},
{id:"mq76",cat:"Medikamente",q:"Metoprolol: Welche Indikation besteht laut SAA?",opts:["Bronchospasmus nach Ausschluss relevanter Allergien oder Unverträglichkeiten","Bradykardie als Monotherapie ohne weitere begleitende Maßnahmen","STEMI/OMI mit nicht schmerzbedingter Tachyarrhythmie oder multiplen VES","Hypertensiver Notfall bei fehlender Besserung unter bisheriger Standardtherapie"],correct:2,explanation:"SAA Metoprolol: STEMI/OMI mit tachykardem Vorhofflimmern > 100/min oder multiplen VES. Cave: BRASH-Syndrom bei Hyperkaliämie!"},
{id:"mq77",cat:"Medikamente",q:"Was ist das BRASH-Syndrom bei Metoprolol?",opts:["Blutdruckabfall bei Vorhofflimmern unter Beachtung der maximalen Tagesdosis laut Fachinformation","Positive Verstärkung einer Kreislaufdepression bei Hyperkaliämie und Betablockade","Bradykardie durch Überdosierung bei gleichzeitiger Gabe von Antiemetika zur Prophylaxe","Bronchospasmus bei Asthma als i.v.-Gabe bei Erwachsenen über 60 kg Körpergewicht"],correct:1,explanation:"BRASH: Bradycardia, Renal failure, AV-block, Shock, Hyperkalemia. Cave bei V.a. Hyperkaliämie im EKG!"},
{id:"mq78",cat:"Medikamente",q:"Metoprolol Maximaldosis laut SAA?",opts:["15 mg als Dauerinfusion über den Perfusor","10 mg als Dauerinfusion über den Perfusor","5 mg gesamt (2+2+1)","2 mg einmalig"],correct:2,explanation:"SAA: 2 mg i.v., Repetition 2 mg + 1 mg = max. 5 mg Gesamtmenge."},
{id:"mq79",cat:"Medikamente",q:"Nalbuphin: Was unterscheidet es von Morphin/Fentanyl?",opts:["Stärkere Wirkung als Dauerinfusion über den Perfusor","Weniger Übelkeit als Dauerinfusion über den Perfusor","Schnellerer Wirkeintritt als Dauerinfusion über den Perfusor","µ-Partialantagonist, Ceiling-Effekt, kein BtM"],correct:3,explanation:"Nalbuphin ist µ-Partialantagonist/κ-Agonist mit Ceiling-Effekt (keine Wirkverstärkung bei Dosissteigerung), geringes Atemdepressionsrisiko, kein BtM."},
{id:"mq80",cat:"Medikamente",q:"Nalbuphin Dosierung < 65 Jahre?",opts:["0,1 mg/kgKG i.v.","0,2 mg/kgKG i.v.","10 mg pauschal","0,5 mg/kgKG i.v."],correct:1,explanation:"SAA: < 65 J: 0,2 mg/kgKG i.v. | ≥ 65 J: 0,1 mg/kgKG i.v. | Repetition bis max. 20 mg. Bei Kindern keine Repetition."},
{id:"mq81",cat:"Medikamente",q:"Paracetamol i.v.: Dosierung bei Pat. > 50 kg?",opts:["1.000 mg als Kurzinfusion über 15 min","500 mg Bolus als Dauerinfusion über den Perfusor","2.000 mg als Dauerinfusion über den Perfusor","15 mg/kgKG immer als Dauerinfusion über den Perfusor"],correct:0,explanation:"SAA: > 50 kg: 1.000 mg i.v. Kurzinfusion 15 min. 15-50 kg: 15 mg/kgKG. Einmalig, keine Repetition."},
{id:"mq82",cat:"Medikamente",q:"Warum ist Paracetamol bei schwerer Leberfunktionsstörung kontraindiziert?",opts:["Hepatotoxischer Metabolit NAPQI kann nicht entgiftet werden","Allergie häufiger i.m. als Alternative bei fehlendem Zugang","Wirkungslos bei stabilen Kreislaufverhältnissen und gesichertem Zugang","Zu schneller Abbau i.m. als Alternative bei fehlendem Zugang"],correct:0,explanation:"Paracetamol-Metabolit NAPQI ist hepatotoxisch und wird normalerweise durch Glutathion entgiftet. Bei Leberinsuffizienz ist dies gestört – Lebensgefahr!"},
{id:"mq83",cat:"Medikamente",q:"Sauerstoff: Ziel-SpO₂ bei COPD-Patient?",opts:["96-100%","94-98%","88-92%","80-85%"],correct:2,explanation:"SAA: Hyperkapnierisiko (COPD, Mukoviszidose, etc.): Ziel 88-92%. Ohne Hyperkapnierisiko: 92-96%."},
{id:"mq84",cat:"Medikamente",q:"Wann gibt man Sauerstoff hochdosiert (15 l/min) ohne Zielwert?",opts:["Bei SpO₂ < 96% als Dauermedikation zur Rezidivprophylaxe nach Erstgabe","Kreislaufstillstand, schwere Atemnot, CO-Intoxikation, Tauchunfall","Bei jedem Notfall bei gleichzeitiger Volumentherapie und Sauerstoffgabe","Immer bei Dyspnoe nach Ausschluss relevanter Allergien oder Unverträglichkeiten und anschließender Re-Evaluation aller erhobenen Befunde nach 10 Minuten"],correct:1,explanation:"SAA: 15 l/min ohne Zielwert bei: kein SpO₂-Signal + kritisch krank, schwere Atemnot, CO-Intoxikation, Tauchunfall."},
{id:"mq85",cat:"Medikamente",q:"Tranexamsäure: Dosierung und Zeitfenster?",opts:["1 g Bolus, jederzeit i.m. als Alternative bei fehlendem Zugang","30 mg/kgKG, innerhalb 1 h rektal als Suppositorium bei Kindern","500 mg, innerhalb 6 h i.m. als Alternative bei fehlendem Zugang","15 mg/kgKG i.v. (max. 1.000 mg), nur innerhalb 3 h nach Trauma"],correct:3,explanation:"SAA: 15 mg/kgKG Kurzinfusion 15 min, max. 1.000 mg. NUR innerhalb der ersten 3 Stunden nach Trauma! Keine Repetition."},
{id:"mq86",cat:"Medikamente",q:"Bei welcher Verletzung wird Tranexamsäure NICHT empfohlen?",opts:["Isoliertes SHT ohne Polytraumatisierung","Schwere Extremitätenblutung gemäß den aktuellen Empfehlungen der zuständigen ärztlichen Leitung","Polytrauma mit hämorrhagischem Schock","Beckenfraktur mit Massenblutung"],correct:0,explanation:"SAA: Bei isoliertem SHT, intrazerebraler Blutung ohne Polytraumatisierung oder GI-Blutungen aktuell NICHT empfohlen."},
{id:"mq87",cat:"Medikamente",q:"Vollelektrolytlösung: Dosierung für Kinder ≤ 12 Jahre?",opts:["5 ml/kgKG","500 ml pauschal","20 ml/kgKG, nach vorheriger Abklärung aller reversiblen Ursachen gemäß Algorithmus","10 ml/kgKG i.v."],correct:3,explanation:"SAA: ≤ 12 J: 10 ml/kgKG i.v. > 12 J: 500-1.000 ml. Repetition möglich."},
{id:"mq88",cat:"Medikamente",q:"Vollelektrolytlösung: Kontraindikation?",opts:["Kardiale Dekompensation / Lungenödem","Anaphylaxie als Dauerinfusion über den Perfusor","Sepsis als Dauerinfusion über den Perfusor","Dehydratation als Dauerinfusion über den Perfusor"],correct:0,explanation:"SAA: Keine VEL bei Hypervolämie (kardiale Dekompensation, Lungenödem, Niereninsuffizienz mit Oligo-/Anurie)."},
{id:"mq89",cat:"Medikamente",q:"Welches Analgetikum ist kein BtM und hat einen Ceiling-Effekt?",opts:["Morphin","Esketamin unter","Fentanyl","Nalbuphin"],correct:3,explanation:"Nalbuphin: µ-Partialantagonist / κ-Agonist, kein BtM nach BtMG, Ceiling-Effekt = keine Wirkverstärkung bei Dosissteigerung."},
// ── NEUE SAA INVASIVE MASSNAHMEN ──
{cat:"Invasive Maßnahmen",q:"Wie hoch darf der maximale Cuffdruck beim LTS-D sein?",opts:["30 cmH₂O","80 cmH₂O","60 cmH₂O","40 cmH₂O"],correct:2,explanation:"SAA: Cuffdruck beim LTS-D maximal 60 cmH₂O. Blocken mittels farbcodierter Spritze mit Cuffdruckmessung."},
{cat:"Invasive Maßnahmen",q:"Wie groß darf die Magensonde im Drainagekanal des LTS-D maximal sein?",opts:["Größe 18 Fr","Größe 10 Fr","Größe 14 Fr","Größe 22 Fr"],correct:0,explanation:"SAA LTS-D: Magensonde in Drainagekanal einführen, maximal Größe 18 Fr."},
{cat:"Invasive Maßnahmen",q:"Welcher maximale Beatmungsdruck gilt beim LTS-D und der Larynxmaske 2. Gen.?",opts:["< 25 mbar","< 40 mbar","< 20 mbar","< 30 mbar"],correct:0,explanation:"SAA LTS-D und Larynxmaske: Beatmungsdruck < 25 mbar. Nur i-gel erlaubt ≤ 40 mbar."},
{cat:"Invasive Maßnahmen",q:"Was deutet bei einem LTS-D darauf hin, dass eine Fehllage vorliegt?",opts:["Thorax hebt sich seitengleich","Patient hustet nach ABCDE-Reevaluation","Magensonde lässt sich nicht vorschieben","Kapnographie zeigt etCO₂, wobei die Wirksamkeit engmaschig kontrolliert werden muss"],correct:2,explanation:"SAA: Lässt sich die Magensonde NICHT vorschieben, weist dies auf Fehllage oder Abknickung der Tubusspitze hin!"},
{cat:"Invasive Maßnahmen",q:"Woran erkennt man bei der LMA Supreme, dass die Größe zu groß gewählt wurde?",opts:["Magensonde passt nicht","Cuff lässt sich nicht blocken","Fixierlasche zur Oberlippe > 2,5 cm","Fixierlasche zur Oberlippe < 1 cm"],correct:2,explanation:"SAA Larynxmaske: LMA Supreme Fixierlasche zur Oberlippe > 2,5 cm = zu groß. < 1 cm = zu klein."},
{cat:"Invasive Maßnahmen",q:"Was ist eine Besonderheit der i-gel im Vergleich zu LTS-D und LMA?",opts:["Nur für Kinder geeignet bei gesichertem Atemweg","Kein Drainagekanal laut aktuellem Algorithmus","Gel-basierter Cuff – kein Blocken nötig","Höherer Cuffdruck (80 cmH₂O)"],correct:2,explanation:"Die i-gel hat einen gel-basierten anatomischen Cuff, der NICHT geblockt werden muss. Beatmungsdruck ≤ 40 mbar."},
{cat:"Invasive Maßnahmen",q:"Was gilt bei der i-gel-Einführung bezüglich der Finger?",opts:["Zeigefinger zum Vorschieben","KEINE Finger in den Mund des Patienten","Finger als Zungendepressor","Finger als Schienung nutzen"],correct:1,explanation:"SAA i-gel: Zum Einführen KEINE Finger in den Mund des Patienten! Einführung mit kontinuierlichem, sanftem Druck am harten Gaumen entlang."},
{cat:"Invasive Maßnahmen",q:"Was ist die Hauptindikation der Laryngoskopie laut SAA?",opts:["Narkoseeinleitung nach Sicherung der Vitalfunktionen","Bolus-Suche und -Entfernung bei Atemwegsverlegung","Endotracheale Intubation unter Beachtung der Kontraindikationen","Kontrolle der EGA-Lage bei dokumentierter Indikation"],correct:1,explanation:"SAA Laryngoskopie: Indikation = Bolus-Suche und -Entfernung bei (sub-)totaler Atemwegsverlegung sowie Kreislaufstillstand unklarer Ursache."},
{cat:"Invasive Maßnahmen",q:"Was ist bei der Laryngoskopie STRENG verboten?",opts:["Macintosh-Spatel mit anschließender Transportentscheidung","Videolaryngoskopie nach initialer Stabilisierung","Blindes Vorschieben/Manipulieren mit Laryngoskop/Magillzange","Absaugen von Sekreten gemäß SOP des Rettungsdienstes"],correct:2,explanation:"SAA Laryngoskopie: Niemals blindes Vorschieben oder Manipulieren mit Laryngoskop oder Magillzange!"},
{cat:"Invasive Maßnahmen",q:"Darf der NotSan bei CPR und freier Sicht intubieren?",opts:["Nein, nie bei fehlenden Kontraindikationen, was jedoch in der aktuellen Situation kontraindiziert wäre","Nur bei Kindern unter Berücksichtigung des klinischen Bildes","Ja – ein Versuch wenn kein FK mehr und Stimmritze eindeutig erkennbar","Nur nach NA-Rücksprache mit Voranmeldung in der Zielklinik"],correct:2,explanation:"SAA Laryngoskopie bei CPR: Falls kein FK mehr und Stimmritze eindeutig erkennbar → endotracheale Intubation (EIN Versuch)."},
{cat:"Invasive Maßnahmen",q:"Was muss beim endobronchialen Absaugen ZWINGEND beachtet werden?",opts:["Ohne Präoxygenierung nach Ausschluss reversibler Ursachen","Nur mit Yankauer-Katheter bei hämodynamischer Instabilität","Absaugen unter maximalem Sog unter Zeitdruck im Einsatzgeschehen","Steriles Arbeiten (Hände, Handschuhe, Katheter)"],correct:3,explanation:"SAA Endobronchiales Absaugen: Steriles Arbeiten unerlässlich! Händedesinfektion, sterile Handschuhe, sterile Absaugkatheter."},
{cat:"Invasive Maßnahmen",q:"In welcher Phase wird der Katheter beim endobronchialen Absaugen eingeführt?",opts:["Inspiration, ohne Sog","Unter kontinuierlichem Sog","Egal wann","Exspiration"],correct:0,explanation:"SAA: Sterilen Absaugkatheter OHNE Sog in der Inspirationsphase einführen. Erst beim Zurückziehen Sog aufbauen (Fingertip)."},
{cat:"Invasive Maßnahmen",q:"Welche Komplikation droht beim endobronchialen Absaugen durch Vagusreiz?",opts:["Hypertonie als initiale Maßnahme vor Transport","Tachykardie","Bronchodilatation","Reflexbradykardie"],correct:3,explanation:"SAA: Cave Bradykardie bei Vagusreiz! Bei symptomatischer Reflexbradykardie Abbruch, ggf. Atropingabe."},
{cat:"Invasive Maßnahmen",q:"Wo ist die korrekte Punktionsstelle für die i.m.-Injektion (SAA)?",opts:["M. gluteus maximus bei gesicherter Diagnose und Indikation","Mittleres Drittel lateraler Oberschenkel, ggf. Oberarm","Unterarm mit begleitender Sauerstofftherapie","Medialer Oberschenkel nach differentialdiagnostischer Abwägung"],correct:1,explanation:"SAA: Mittleres Drittel lateraler Oberschenkel, ggf. Oberarm. Punktion senkrecht, langsame Injektion."},
{cat:"Invasive Maßnahmen",q:"Für welche Medikamente ist die i.m.-Gabe laut SAA zugelassen?",opts:["Epinephrin, Glucagon, Opioide, Esketamin, Midazolam","Alle SAA-Medikamente im Rahmen der Notfallversorgung","Nur Epinephrin bei persistierender Symptomatik trotz Erstmaßnahmen","Nur Analgetika nach Anlage eines venösen Zugangs"],correct:0,explanation:"SAA i.m.: Epinephrin (Anaphylaxie), Glucagon (Hypoglykämie), Opioide + Esketamin (Analgesie), Midazolam (Krampf)."},
{cat:"Invasive Maßnahmen",q:"Was ist eine wichtige Kontraindikation der i.m.-Injektion?",opts:["Adipositas gemäß den Empfehlungen des ÄLRD","Kreislaufstillstand oder manifester Schock","Alter > 70 unter Beachtung der Dosierungsgrenzen","Schmerzen bei fortbestehender klinischer Verschlechterung"],correct:1,explanation:"SAA: Bei Kreislaufstillstand/Schock ist die i.m.-Resorption unzuverlässig → i.v. oder i.o. bevorzugen!"},
{cat:"Invasive Maßnahmen",q:"Wie viel ml dürfen maximal pro Nasenloch intranasal verabreicht werden?",opts:["2 ml","1 ml","0,5 ml","3 ml"],correct:1,explanation:"SAA Intranasal: Max. 1 ml pro Nasenloch! Daher höchstkonzentrierte Lösung, kleinstes Volumen wählen."},
{cat:"Invasive Maßnahmen",q:"Was wird für die intranasale Gabe zwingend benötigt?",opts:["Spezialkanüle mit paralleler Vorbereitung des Transports","Nasentropfenflasche nach dokumentierter Erstuntersuchung","Zerstäuber (MAD) an Luer-Lock-Anschluss","Vernebelungssystem unter Einbeziehung der Patientenanamnese"],correct:2,explanation:"SAA: Zerstäuber an Luer-Lock-Anschluss der Spritze verbinden. Spritzenstempel zügig vorschieben."},
{cat:"Invasive Maßnahmen",q:"Für welche Indikationen ist die intranasale Gabe zugelassen (SAA)?",opts:["Status epilepticus, Schmerzmedikation, Hypoglykämie","Nur Schmerzmedikation bei fehlendem Ansprechen auf Ersttherapie","Nur Midazolam als Eskalationsmaßnahme bei Therapieversagen","Nur Glucagon unter Berücksichtigung des Patientenalters"],correct:0,explanation:"SAA Intranasal: Status epilepticus (Midazolam), Schmerzmedikation, Hypoglykämie (Glucagon)."},
{cat:"Invasive Maßnahmen",q:"Was ist die korrekte Reihenfolge bei der achsengerechten Immobilisation?",opts:["Warten auf Röntgenbild nach Erhebung eines Basis-Monitorings","Distal ziehen + proximal fixieren, achsengerechten Stand wiederherstellen","Nur schienen, nicht reponieren mit regelmäßiger Verlaufskontrolle","Erst fixieren, dann ziehen bei Verdacht auf kritische Verschlechterung und anschließende Reevaluation nach spätestens 5 Minuten"],correct:1,explanation:"SAA: Distaler Abschnitt wird gezogen, proximaler fixiert. Gegensinnig zum Traumamechanismus. Zügig, nicht unterbrochen."},
{cat:"Invasive Maßnahmen",q:"Was muss bei Immobilisation VOR und NACH Anlage dokumentiert werden?",opts:["Durchblutung, Motorik, Sensibilität (DMS)","Blutdruck unter Beachtung möglicher Wechselwirkungen","Nur Schmerzintensität als leitliniengerechte Notfallmaßnahme","Röntgenbefund nach klinischer Einschätzung"],correct:0,explanation:"SAA: DMS-Prüfung und Dokumentation vor UND nach Anlage. Regelmäßige Überprüfung im Verlauf."},
{cat:"Invasive Maßnahmen",q:"Welche NIV-Starteinstellungen gelten bei Hypoxie-führendem Lungenödem (SAA)?",opts:["FiO₂ 0,4 / PEEP 0 / PS 5 gemäß Behandlungspfad","FiO₂ 0,6 / PEEP 10 / PS 10 bei stabilen Kreislaufverhältnissen","FiO₂ 1,0 / PEEP 5 / PS 0 mbar, PEEP steigern","FiO₂ 1,0 / PEEP 0 / PS 12 unter kontinuierlichem Monitoring"],correct:2,explanation:"SAA CPAP/NIV: Hypoxie führend → FiO₂ 1,0 / PEEP 5 / PS 0. PEEP steigern. Hyperkapnie: PEEP 0, PS 5, PS steigern."},
{cat:"Invasive Maßnahmen",q:"Welche NIV-Starteinstellungen gelten bei Hyperkapnie-führender COPD (SAA)?",opts:["FiO₂ 1,0 / PEEP 10 / PS 10 nach ABCDE-Reevaluation","FiO₂ 1,0 / PEEP 5 / PS 0 bei gesichertem Atemweg","FiO₂ 0,21 / PEEP 10 / PS 0 laut aktuellem Algorithmus","FiO₂ 0,4-1,0 / PEEP 0 / PS 5 mbar, PS steigern"],correct:3,explanation:"SAA NIV bei Hyperkapnie: FiO₂ 0,4-1,0, PEEP 0, PS 5 mbar. Initial PS steigern (5, 8, 12 mbar nach Tidalvolumen/etCO₂)."},
{cat:"Invasive Maßnahmen",q:"Ab welchem RRsyst ist NIV/CPAP kontraindiziert (SAA)?",opts:["< 90 mmHg","< 120 mmHg","< 80 mmHg","< 100 mmHg"],correct:0,explanation:"SAA CPAP/NIV: Kontraindiziert bei hämodynamischer Instabilität / Schock / Hypotonie mit RRsyst < 90 mmHg."},
{id:"mq90",cat:"Medikamente",q:"Welche ASS-Formulierung wird laut SAA im Rettungsdienst bevorzugt?",opts:["ASS-Granulat als Dauerinfusion über den Perfusor","500 mg Brausetablette als Dauerinfusion über den Perfusor","100 mg Tablette oral als Dauerinfusion über den Perfusor","500 mg Trockensubstanz + 5 ml Lösungsmittel i.v."],correct:3,explanation:"SAA: ASS wird als 250 mg i.v. (aus 500 mg Trockensubstanz + 5 ml Lösungsmittel) oder 200 mg oral gegeben."},
{id:"mq91",cat:"Medikamente",q:"Warum ist ASS im letzten Trimenon der Schwangerschaft kontraindiziert?",opts:["Allergierisiko erhöht als Monotherapie ohne weitere begleitende Maßnahmen","Risiko eines vorzeitigen Verschlusses des Ductus arteriosus Botalli","Kein Effekt bei fehlender Besserung unter bisheriger Standardtherapie","Hyperglykämie unter Beachtung der maximalen Tagesdosis laut Fachinformation"],correct:1,explanation:"ASS hemmt die Prostaglandinsynthese → Risiko des vorzeitigen Verschlusses des Ductus arteriosus im letzten Trimenon."},
{id:"mq92",cat:"Medikamente",q:"Amiodaron: Warum ist eine bekannte Jod-Allergie eine Kontraindikation?",opts:["Amiodaron enthält Jod im Molekül","Kreuzreaktion mit Kontrastmittel","Interaktion mit Schilddrüse","Jod verstärkt die Bradykardie, wobei dies in der aktuellen Fachliteratur kontrovers diskutiert wird"],correct:0,explanation:"Amiodaron ist ein jodhaltiges Antiarrhythmikum. Jod-Allergie ist daher eine absolute Kontraindikation."},
{id:"mq93",cat:"Medikamente",q:"Atropin: Maximaldosis und Repetitionsintervall bei instabiler Bradykardie?",opts:["Max. 6 mg, alle 2 min als Dauerinfusion über den Perfusor","Max. 0,5 mg einmalig als Dauerinfusion über den Perfusor","Max. 1 mg, alle 10 min","Max. 3 mg, alle 3-5 min wiederholbar"],correct:3,explanation:"SAA: Atropin 0,5 mg i.v., alle 3-5 min wiederholbar, max. Gesamtdosis 3 mg."},
{id:"mq94",cat:"Medikamente",q:"Welches Medikament ist bei Nierenkoliken laut aktueller Leitlinie NICHT mehr angezeigt?",opts:["Butylscopolamin","Paracetamol","Metamizol","Ibuprofen nach sorgfältiger"],correct:0,explanation:"SAA Butylscopolamin: 'Bei Nierenkoliken laut Leitlinie (AWMF 043-025) nicht mehr angezeigt.'"},
{id:"mq95",cat:"Medikamente",q:"Dimenhydrinat: Welche Applikation ist bei Kindern ab 6 kg möglich?",opts:["Rektal als Suppositorium (40 mg)","Inhalation als Dauerinfusion über den Perfusor","i.m. Injektion als Dauerinfusion über den Perfusor","i.v. Bolus als Dauerinfusion über den Perfusor"],correct:0,explanation:"SAA: Dimenhydrinat bei Kindern ab 6 kg als Supp. 40 mg rektal. i.v.-Gabe erst ab 14 Jahre."},
{id:"mq96",cat:"Medikamente",q:"Dimetinden: Indikation im Rettungsdienst?",opts:["Allergische Reaktion / Anaphylaxie (H1-Blocker)","Schmerzen sublingual bei kooperativem Patienten","Bradykardie als Dauerinfusion über den Perfusor","Übelkeit sublingual bei kooperativem Patienten"],correct:0,explanation:"SAA: Dimetinden ist ein H1-Antihistaminikum für allergische Reaktionen / Anaphylaxie."},
{id:"mq97",cat:"Medikamente",q:"Epinephrin bei Reanimation: Dosierung Erwachsene und Zeitpunkt?",opts:["0,3 mg i.v. einmalig unter","0,5 mg i.m. alle 5 min","1 mg i.v. alle 3-5 min","2 mg i.v. alle 10 min"],correct:2,explanation:"SAA: Epinephrin 1 mg i.v. bei nicht defibrillierbaren Rhythmen sofort, bei defibrillierbaren nach 3. Schock, dann alle 3-5 min."},
{id:"mq98",cat:"Medikamente",q:"Epinephrin bei Anaphylaxie Grad III: Dosierung Kind (15-30 kg)?",opts:["0,5 mg i.m. als Dauerinfusion über den Perfusor","0,01 mg i.m. als Dauerinfusion über den Perfusor","1 mg i.v. als Dauerinfusion über den Perfusor","0,15 mg (150 µg) i.m."],correct:3,explanation:"SAA: Epinephrin bei Anaphylaxie Kinder 15-30 kg: 0,15 mg (150 µg) i.m., >30 kg: 0,3 mg, Erwachsene: 0,5 mg."},
{id:"mq99",cat:"Medikamente",q:"Esketamin: Warum wird es gegenüber Ketamin bevorzugt?",opts:["Doppelte Potenz bei halber Dosierung, weniger Nebenwirkungen","Schnellerer Wirkeintritt als Dauerinfusion über den Perfusor","Billigerer Preis in doppelter Dosis bei schwerer Symptomatik","Keine Toleranzentwicklung als Dauerinfusion über den Perfusor"],correct:0,explanation:"Esketamin (S-Enantiomer) hat die doppelte analgetische Potenz von Ketamin bei geringeren Nebenwirkungen."},
{id:"mq100",cat:"Medikamente",q:"Esketamin: Dosierung i.v. zur Analgesie beim Erwachsenen?",opts:["1 mg/kgKG i.v, in Kombination mit","0,5 mg/kgKG i.v.","2 mg/kgKG i.v.","0,125-0,25 mg/kgKG i.v."],correct:3,explanation:"SAA: Esketamin 0,125-0,25 mg/kgKG i.v. zur Analgesie. Höhere Dosen für Narkoseeinleitung (nur NA)."},
{id:"mq101",cat:"Medikamente",q:"Fentanyl: Welcher Applikationsweg ist bei Kindern besonders geeignet?",opts:["i.m. als Dauerinfusion über den Perfusor","Intranasal (1,5 µg/kgKG)","Rektal als Dauerinfusion über den Perfusor","i.v. Bolus als Dauerinfusion über den Perfusor"],correct:1,explanation:"SAA: Fentanyl kann intranasal gegeben werden (1,5 µg/kgKG). Besonders bei Kindern als nadelfreie Alternative geeignet."},
{id:"mq102",cat:"Medikamente",q:"Furosemid: Ab welchem Alter darf es laut SAA angewendet werden?",opts:["Ab 12 Jahre","Ab 18 Jahre","Keine Altersbegrenzung","Ab 6 Jahre"],correct:1,explanation:"SAA: Furosemid – Keine Anwendung bei Patienten < 18 Jahre."},
{id:"mq103",cat:"Medikamente",q:"Glucagon: Dosierung bei Hypoglykämie Erwachsene?",opts:["0,5 mg i.v. als Dauerinfusion über den Perfusor","2 mg oral als Dauerinfusion über den Perfusor","1 mg i.m. oder s.c.","0,1 mg/kgKG als Dauerinfusion über den Perfusor"],correct:2,explanation:"SAA: Glucagon bei Hypoglykämie: Erw. und Kinder >25 kg: 1 mg i.m. oder s.c. Kinder <25 kg: 0,5 mg."},
{id:"mq104",cat:"Medikamente",q:"Glucose 40%: Maximale Bolusgabe Erwachsene?",opts:["0,5 g/kgKG i.v., bei 70 kg also ca. 80 ml G40%","200 ml Bolus als Dauerinfusion über den Perfusor","20 ml einmalig als Dauerinfusion über den Perfusor","1 g/kgKG sublingual bei kooperativem Patienten"],correct:0,explanation:"SAA: Glucose Erw. 0,5 g/kgKG i.v. (=1,25 ml/kgKG G40%). Repetition bis BZ-Normalisierung."},
{id:"mq105",cat:"Medikamente",q:"Glyceroltrinitrat: Zeitabstand nach PDE-5-Hemmer (Sildenafil)?",opts:["Mind. 24 Stunden, bei Tadalafil 48 Stunden","12 Stunden als Dauerinfusion über den Perfusor","6 Stunden als Dauerinfusion über den Perfusor","Keine Wartezeit nötig als Dauerinfusion über den Perfusor"],correct:0,explanation:"SAA: KI für Nitrate bei PDE-5-Hemmer: Sildenafil/Vardenafil mind. 24h, Tadalafil mind. 48h."},
{id:"mq106",cat:"Medikamente",q:"Heparin: Dosierung bei ACS laut SAA?",opts:["10.000 IE i.v.","500 IE/kgKG nach Sicherung der Vitalfunktionen","1.000 IE s.c, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","5.000 IE i.v. Bolus"],correct:3,explanation:"SAA: Heparin 5.000 IE i.v. Bolus beim Akuten Koronarsyndrom."},
{id:"mq107",cat:"Medikamente",q:"Midazolam: Dosierung intranasal beim Kind (13-40 kg) zur Krampfdurchbrechung?",opts:["0,2 mg/kgKG intranasal (max. 10 mg)","1 mg pauschal als Dauerinfusion über den Perfusor","0,05 mg/kgKG als Dauerinfusion über den Perfusor","0,5 mg/kgKG i.v. als Dauerinfusion über den Perfusor"],correct:0,explanation:"SAA Midazolam: Kinder 13-40 kg: 0,2 mg/kgKG intranasal (max. 10 mg). >40 kg: 10 mg. Auch buccal möglich."},
{id:"mq108",cat:"Medikamente",q:"Morphin: Ab welchem NRS-Wert ist die Gabe laut SAA indiziert?",opts:["NRS ≥ 6","NRS ≥ 8, abhängig von","NRS ≥ 3","NRS ≥ 4"],correct:0,explanation:"SAA: Morphin (und Nalbuphin) bei starken/stärksten Schmerzen NRS ≥ 6. Nicht-Opioide bereits ab NRS ≥ 3."},
{id:"mq109",cat:"Medikamente",q:"Naloxon: Dosierung zur Opioid-Antagonisierung beim Erwachsenen?",opts:["1 mg s.c. verdünnt in 100 ml NaCl über 20 Minuten","0,4 mg i.m. einmalig als Dauerinfusion über den Perfusor","0,04-0,1 mg i.v. titriert, Repetition bis Wirkung","2 mg i.v. Bolus als Dauerinfusion über den Perfusor"],correct:2,explanation:"SAA: Naloxon vorsichtig titrieren (0,04-0,1 mg i.v.), Repetition bis gewünschte Wirkung. Cave: kurze HWZ!"},
{id:"mq110",cat:"Medikamente",q:"Prednisolon: Dosierung bei Anaphylaxie Erwachsene?",opts:["100 mg rektal","500 mg oral","50 mg i.v.","250 mg i.v."],correct:3,explanation:"SAA: Prednisolon bei Anaphylaxie Erw. 250 mg i.v. Kinder 2 mg/kgKG (max. 100 mg)."},
{id:"mq111",cat:"Medikamente",q:"Salbutamol: Dosierung Vernebelung Erwachsene?",opts:["1 Hub i.m. als Alternative bei fehlendem Zugang","10 Hübe sublingual bei kooperativem Patienten","4 Hübe (0,4 mg) oder 1 Fertiginhalat vernebelt","2 mg i.v. rektal als Suppositorium bei Kindern"],correct:2,explanation:"SAA: Salbutamol Erw. 4 Hübe (je 0,1 mg) oder 1 Fertiginhalat (2,5 ml) vernebelt. Repetition nach 15 min."},
{id:"mq112",cat:"Medikamente",q:"Welches Analgetikum hat laut SAA KEINEN Ceiling-Effekt?",opts:["Paracetamol","Nalbuphin","Morphin","Ibuprofen"],correct:2,explanation:"Morphin als reiner µ-Agonist hat keinen Ceiling-Effekt – Dosissteigerung = Wirkungssteigerung. Nalbuphin hat einen Ceiling-Effekt."},
{id:"mq113",cat:"Medikamente",q:"Welches Medikament ist gleichzeitig Analgetikum und Antipyretikum, aber KEIN NSAR?",opts:["Esketamin","Paracetamol","Ibuprofen","ASS als Dauerinfusion"],correct:1,explanation:"Paracetamol wirkt analgetisch und antipyretisch, hemmt aber nicht die Cyclooxygenase peripher → kein NSAR."},
{id:"mq114",cat:"Medikamente",q:"Welche Medikamente dürfen beim ACS NICHT gleichzeitig gegeben werden?",opts:["Morphin und Esketamin","ASS und Heparin als Dauerinfusion über den Perfusor","Fentanyl und Naloxon","Metoprolol und Glyceroltrinitrat"],correct:3,explanation:"SAA Metoprolol: Beide hypotensiv wirksam, daher keine zeitgleiche Gabe von Metoprolol und Glyceroltrinitrat!"},
{id:"mq115",cat:"Medikamente",q:"Ipratropiumbromid und Salbutamol: Was ist der Unterschied im Wirkmechanismus?",opts:["Gleicher Mechanismus, verschiedene Stärke als Dauerinfusion über den Perfusor","Ipratropium: Schmerzmittel in doppelter Dosis bei schwerer Symptomatik","Salbutamol: Parasympatholytikum sublingual bei kooperativem Patienten","Ipratropium: Parasympatholytikum, Salbutamol: Beta-2-Sympathomimetikum"],correct:3,explanation:"Ipratropiumbromid blockiert muskarinische Rezeptoren (Parasympatholytikum), Salbutamol stimuliert Beta-2-Rezeptoren (Sympathomimetikum)."},
{id:"mq116",cat:"Medikamente",q:"Tranexamsäure: Warum Kurzinfusion über 15 min statt Bolus?",opts:["Zu schnelle i.v.-Gabe verursacht Hypotonie mit Bewusstlosigkeit","Wirkungsverlust bei Bolus sublingual bei kooperativem Patienten","Extravasation bei gleichzeitiger Gabe von Antiemetika zur Prophylaxe","Allergierisiko bei Bolus sublingual bei kooperativem Patienten"],correct:0,explanation:"SAA: 'Unwohlsein mit Hypotonie mit oder ohne Bewusstlosigkeit im Allgemeinen nach einer zu schnellen i.v.-Applikation.'"},
{id:"mq117",cat:"Medikamente",q:"Vollelektrolytlösung: Wie lange hält der intravasale Volumeneffekt an?",opts:["5-10 Minuten","2-3 Stunden","6 Stunden","20-30 Minuten"],correct:3,explanation:"SAA: 'Relativ kurzzeitiger intravasaler Volumeneffekt (20-30 Minuten).' Deshalb oft Repetition nötig."},
{id:"mq118",cat:"Medikamente",q:"Sauerstoff: Was bedeutet 'Hyperkapnierisiko' und welche Patienten betrifft es?",opts:["Risiko bei Kindern sublingual bei kooperativem Patienten","Zu viel O₂ bei Gesunden als Dauerinfusion über den Perfusor","Gefahr bei Anaphylaxie als Dauerinfusion über den Perfusor","Gefahr der CO₂-Retention bei COPD, Mukoviszidose, BMI>40"],correct:3,explanation:"SAA: Hyperkapnierisiko bei COPD, Mukoviszidose, Thoraxdeformitäten, neuromuskulären Erkrankungen, Adipositas per magna (BMI>40). Ziel SpO₂ 88-92%."},
{id:"mq119",cat:"Medikamente",q:"Welche Medikamente können laut SAA intranasal gegeben werden?",opts:["Nur Midazolam sublingual bei kooperativem Patienten","Nur Fentanyl und Esketamin als Dauerinfusion über den Perfusor","Midazolam, Fentanyl, Nalbuphin, Esketamin, Glucagon","Alle Opioide sublingual bei kooperativem Patienten"],correct:2,explanation:"SAA: Intranasale Gabe ist für Midazolam, Fentanyl, Nalbuphin, Esketamin und Glucagon beschrieben."},
{id:"mq120",cat:"Medikamente",q:"Lidocain vs. Amiodaron bei Reanimation: Wann wird Lidocain bevorzugt?",opts:["Gleichwertige Alternative – lokale Verfügbarkeit entscheidet","Nur nach dem 5. Schock sublingual bei kooperativem Patienten","Nur bei Kindern in doppelter Dosis bei schwerer Symptomatik","Lidocain immer besser sublingual bei kooperativem Patienten"],correct:0,explanation:"SAA: Lidocain ist eine gleichwertige Alternative zu Amiodaron bei Kammerflimmern/pVT. Die Wahl richtet sich nach lokaler Verfügbarkeit."},
{id:"mq121",cat:"Medikamente",q:"Nalbuphin: Warum ist es bei Opioidabhängigkeit kontraindiziert?",opts:["Interaktion mit Methadon als Dauerinfusion über den Perfusor","Als µ-Partialantagonist kann es Entzugssymptome auslösen","Zu starke Wirkung sublingual bei kooperativem Patienten","Wirkungslos bei Toleranz als Dauerinfusion über den Perfusor"],correct:1,explanation:"SAA: Nalbuphin als µ-Partialantagonist verdrängt µ-Agonisten vom Rezeptor → akutes Entzugssyndrom bei Opioidabhängigkeit/Substitution."},
{id:"mq122",cat:"Medikamente",q:"Ibuprofen i.v.: Ab welchem Alter und in welcher Dosierung?",opts:["Ab 18 Jahre, 600 mg i.v.","Ab 12 Jahre, 400 mg i.v gemäß den","Keine i.v.-Gabe laut SAA","Ab 6 Jahre, 200 mg i.v."],correct:0,explanation:"SAA: i.v.-Gabe möglich: 600 mg i.v. ab dem 18. Lebensjahr. Tageshöchstdosis 1.200 mg."},
{id:"mq123",cat:"Medikamente",q:"Metoprolol bei STEMI/OMI: Ab welcher Herzfrequenz bei Vorhofflimmern indiziert?",opts:["> 100/min","> 60/min und anschließen","> 80/min","> 120/min"],correct:0,explanation:"SAA: Metoprolol bei STEMI/OMI mit nicht schmerzbedingtem tachykardem Vorhofflimmern > 100/min."},
{id:"mq124",cat:"Medikamente",q:"Paracetamol rektal: Dosierung für 5-jähriges Kind (20 kg)?",opts:["250 mg","500 mg","1.000 mg","125 mg"],correct:0,explanation:"SAA: Paracetamol rektal: 13-25 kgKG (2-8 J): 250 mg. 26-43 kgKG (8-12 J): 500 mg."},
{id:"mq125",cat:"Medikamente",q:"Welches Medikament hat die längste Wirkdauer laut SAA?",opts:["Glyceroltrinitrat (20 min)","ASS (Tage – Lebensdauer der Thrombozyten)","Fentanyl (30 min) als Dauerinfusion über den Perfusor","Atropin (4 Stunden) als Dauerinfusion über den Perfusor"],correct:1,explanation:"SAA ASS: 'Wirkdauer: Tage (Lebensdauer der Thrombozyten)' – irreversible Hemmung der Thrombozytenaggregation."},
{id:"mq126",cat:"Medikamente",q:"Glucagon: Wann ist die i.m.-Gabe besonders sinnvoll?",opts:["Hypoglykämie ohne i.v.-Zugang","Anaphylaxie als Dauerinfusion über den Perfusor","Bradykardie als Dauerinfusion über den Perfusor","Krampfanfall als Dauerinfusion über den Perfusor"],correct:0,explanation:"SAA: Glucagon 1 mg i.m. ist die Alternative zur Glucosegabe i.v. bei Hypoglykämie ohne venösen Zugang."},
{id:"mq127",cat:"Medikamente",q:"Epinephrin vernebelt: Dosierung und Indikation?",opts:["10 mg bei Lungenödem als i.v.-Gabe bei Erwachsenen über 60 kg Körpergewicht, was in der klinischen Praxis allerdings nur selten angewendet wird","0,5 mg bei Asthma bei stabilen Kreislaufverhältnissen und gesichertem Zugang","1 mg bei Bronchospasmus in doppelter Dosis bei schwerer Symptomatik","4 mg (4 ml 1:1000) bei Pseudokrupp / Obstruktion der oberen Atemwege"],correct:3,explanation:"SAA/BPR: Epinephrin vernebelt 4 mg bei Stridor/oberer Atemwegsobstruktion (Pseudokrupp, allergisches Larynxödem)."},
{id:"mq128",cat:"Medikamente",q:"Dimetinden: Dosierung bei Anaphylaxie Erwachsene?",opts:["1 mg pauschal als Dauerinfusion über den Perfusor","0,1 mg/kgKG i.v. (ca. 1 Ampulle = 4 mg)","10 mg i.v. als Dauerinfusion über den Perfusor","0,5 mg/kgKG als Dauerinfusion über den Perfusor"],correct:1,explanation:"SAA: Dimetinden 0,1 mg/kgKG i.v. Bei Erw. ca. 8 mg (2 Amp. à 4 mg)."},
{id:"mq129",cat:"Medikamente",q:"Furosemid: Dosierung beim kardialen Lungenödem?",opts:["20-40 mg i.v.","5 mg i.v.","80 mg oral","100 mg i.v."],correct:0,explanation:"SAA: Furosemid 20-40 mg langsam i.v. beim kardialen Lungenödem. Max. 40 mg."},
{id:"mq130",cat:"Medikamente",q:"Esketamin: Welche UAW muss besonders beachtet werden?",opts:["Blutungsneigung in doppelter Dosis bei schwerer Symptomatik","Bradykardie als Dauermedikation zur Rezidivprophylaxe nach Erstgabe","Atemdepression wie bei Opioiden als Dauerinfusion über den Perfusor","Hypersalivation, Laryngospasmus, psychomimetische Reaktionen"],correct:3,explanation:"SAA: UAW Esketamin: Hypersalivation, Laryngospasmus (bes. Kinder), psychomimetische Reaktionen (Albträume, Halluzinationen)."},
{id:"mq131",cat:"Medikamente",q:"Morphin: Dosierung i.v. beim Erwachsenen < 65 Jahre?",opts:["10 mg Bolus als Dauerinfusion über den Perfusor","0,5 mg/kgKG i.v. als Dauerinfusion über den Perfusor","1 mg/kgKG i.v. als Dauerinfusion über den Perfusor","0,05-0,1 mg/kgKG i.v. titriert"],correct:3,explanation:"SAA: Morphin Erw. < 65 J: 0,05-0,1 mg/kgKG i.v. langsam titriert. ≥ 65 J: 0,03-0,05 mg/kgKG."},
{id:"mq132",cat:"Medikamente",q:"Welches Medikament wird bei Opiatintoxikation als Antidot eingesetzt?",opts:["Naloxon","Dimetinden","Atropin","Glucagon"],correct:0,explanation:"Naloxon ist der spezifische Opioid-Antagonist. Cave: HWZ kürzer als die meisten Opioide → Rebound möglich!"},
{id:"mq133",cat:"Medikamente",q:"Prednisolon: Welche Formulierung wird bei Pseudokrupp (Kind) bevorzugt?",opts:["250 mg i.v. als Dauerinfusion über den Perfusor","Suppositorium 100 mg rektal","Inhalation als Dauerinfusion über den Perfusor","Tablette oral als Dauerinfusion über den Perfusor"],correct:1,explanation:"SAA/BPR: Prednisolon bei Pseudokrupp/obstruktive Laryngitis: 100 mg Supp. rektal (Kinder). Systemische Wirkung nach 30-60 min."},
{id:"mq134",cat:"Medikamente",q:"Heparin: Welche Kontraindikation ist beim Polytrauma besonders relevant?",opts:["Hypertonie bei gleichzeitiger Volumentherapie und Sauerstoffgabe","Alter > 80 nach Ausschluss relevanter Allergien oder Unverträglichkeiten","Diabetes als Monotherapie ohne weitere begleitende Maßnahmen","Heparininduzierte Thrombozytopenie (HIT) in der Anamnese"],correct:3,explanation:"SAA: Kontraindikation Heparin: HIT (Heparininduzierte Thrombozytopenie) in der Anamnese, aktive Blutungen."},
{id:"iq51",cat:"Invasive Maßnahmen",q:"i.v.-Zugang: Welche Vene sollte möglichst NICHT punktiert werden?",opts:["Unterarm unter fluoroskopischer Führung im Schockraum","Fußrücken nur bei gesicherter Atemwegskontrolle und Monitoring","Ellenbeuge (V. cubitalis)","Handrücken nach Rücksprache mit dem diensthabenden Chirurgen"],correct:2,explanation:"SAA: 'Geeignete Punktionsstelle suchen (von peripher nach zentral), Ellenbeuge möglichst vermeiden' – wegen Gelenkbewegung/Abknickung."},
{id:"iq52",cat:"Invasive Maßnahmen",q:"i.v.-Zugang: Was ist die korrekte Reihenfolge bei der Anlage?",opts:["Punktionsstelle suchen → Desinfektion → Venenstau → erneute Desinfektion → Punktion","Punktion → Desinfektion → Fixierung bei fehlenden Kontraindikationen","Venenstau → Punktion → Desinfektion unter Berücksichtigung des Alters","Desinfektion → Punktion → Venenstau nach aktueller Leitlinienempfehlung"],correct:0,explanation:"SAA: Korrekte Reihenfolge: Stelle suchen → Reinigung/Desinfektion → Venenstau → erneute Hautdesinfektion → Punktion."},
{id:"iq53",cat:"Invasive Maßnahmen",q:"i.v.-Zugang: Grüne Verweilkanüle (18G) – Durchflussrate?",opts:["Ca. 96 ml/min","Ca. 36 ml/min","Ca. 343 ml/min","Ca. 196 ml/min"],correct:0,explanation:"SAA: 18G (grün, 1,3 mm): ca. 96 ml/min. 16G (grau): 196 ml/min. 14G (orange): 343 ml/min."},
{id:"iq54",cat:"Invasive Maßnahmen",q:"i.v.-Zugang: Welche Extremität ist bei Dialyse-Shunt kontraindiziert?",opts:["Extremität mit Dialyse-Shunt","Nur der Fuß unter sterilen Bedingungen mit Handschuhen und Abdeckung","Jeder Unterarm nach ultraschallgestützter Lagekontrolle","Kontralaterale Hand"],correct:0,explanation:"SAA: KI für i.v.-Zugang: Dialyse-Shunt, Z.n. axillärer Lymphknotenentfernung, paretische/verletzte Extremität."},
{id:"iq55",cat:"Invasive Maßnahmen",q:"i.o.-Zugang: Standard-Punktionsort?",opts:["Sternum mit vorheriger Anästhesie der Punktionsstelle","Beckenkamm unter fluoroskopischer Führung im Schockraum","Distaler Femur nur bei gesicherter Atemwegskontrolle und Monitoring","Proximale Tibia medial der Tuberositas tibiae"],correct:3,explanation:"SAA: 'Punktionsort: proximale Tibia medial der Tuberositas tibiae.'"},
{id:"iq56",cat:"Invasive Maßnahmen",q:"i.o.-Zugang: Was wird NICHT durch den NotSan gegeben?",opts:["Kristalloide Lösung nach Rücksprache mit dem diensthabenden Chirurgen","Epinephrin unter sterilen Bedingungen mit Handschuhen und Abdeckung","Amiodaron nach ultraschallgestützter Lagekontrolle","Lidocain (Schmerztherapie an Punktionsstelle)"],correct:3,explanation:"SAA: 'Keine Lidocaingabe durch NotSan' am i.o.-Zugang. Schmerztherapie an Punktionsstelle ist NA-Aufgabe."},
{id:"iq57",cat:"Invasive Maßnahmen",q:"i.o.-Zugang: Welche Kontraindikation ist NICHT korrekt?",opts:["Intakte Tibia am ipsilateralen Bein","Fraktur der entsprechenden Tibia","Infektion an der Punktionsstelle","Vorheriger Punktionsversuch am selben Knochen"],correct:0,explanation:"SAA KI i.o.: Fraktur der Tibia, vorheriger Versuch am selben Knochen, Infektion/Endoprothese/Implantat, massive Weichteilschäden. Eine intakte Tibia ist gerade KEIN KI."},
{id:"iq58",cat:"Invasive Maßnahmen",q:"LTS-D: Maximaler Cuffdruck?",opts:["30 cm H₂O","80 cm H₂O","40 cm H₂O, was in der","60 cm H₂O"],correct:3,explanation:"SAA LTS-D: 'Cuffdruckmessung, Cuffdruck maximal 60 cm H₂O.'"},
{id:"iq59",cat:"Invasive Maßnahmen",q:"LTS-D: Maximaler Beatmungsdruck?",opts:["< 15 mbar nach","< 60 mbar","< 25 mbar","< 40 mbar"],correct:2,explanation:"SAA LTS-D: 'Beatmungsdruck < 25 mbar.' Bei i-gel: ≤ 40 mbar."},
{id:"iq60",cat:"Invasive Maßnahmen",q:"LTS-D: Was deutet auf eine Fehllage hin?",opts:["Beidseits gleiches Atemgeräusch","Magensonde lässt sich nicht vorschieben","Positives Kapnographie-Signal und anschließender Re-Evaluation aller erhobenen Befunde nach 10 Minuten","Symmetrische Thoraxbewegung"],correct:1,explanation:"SAA: 'Lässt sich Magensonde nicht vorschieben, weist dies auf Fehllage oder Abknickung der Tubusspitze hin.'"},
{id:"iq61",cat:"Invasive Maßnahmen",q:"LTS-D: Maximale Größe der Magensonde?",opts:["12 Fr nach sorgfälti","18 Fr","8 Fr","24 Fr"],correct:1,explanation:"SAA LTS-D: 'Magensonde in Drainagekanal einführen (max. Größe 18 Fr).'"},
{id:"iq62",cat:"Invasive Maßnahmen",q:"Larynxmaske 2. Generation: Was ist der 'Bubble Test'?",opts:["Messung des Beatmungsdrucks laut Herstellerangabe","Test der Cuff-Dichtigkeit bei gesicherter Diagnose","Überprüfung der Tubusgröße gemäß SOP des ÄLRD unter kontinuierlichem Monitoring der Vitalparameter während des Transports","Erfolgsprüfung – Drainagekanal mit Gel verschließen, Blasenbildung zeigt korrekte Lage"],correct:3,explanation:"SAA: Larynxmaske Erfolgsprüfung: 'Drainagekanal mit einem Tropfen Gel verschließen → Bubble Test und Suprasternal Notch Test.'"},
{id:"iq63",cat:"Invasive Maßnahmen",q:"Larynxmaske: Welche Größe soll gewählt werden?",opts:["Kleinstmögliche","Mittlere Größe immer","Nach Körpergewicht genau, was in der klinischen Praxis allerdings nur selten angewendet wird","Größtmögliche Maskengröße"],correct:3,explanation:"SAA: 'Auswahl der richtigen Größe (größtmögliche Maskengröße wählen).'"},
{id:"iq64",cat:"Invasive Maßnahmen",q:"i-gel: Besonderheit beim Beatmungsdruck im Vergleich zu LTS-D?",opts:["Gleicher Druck mit vorheriger Anästhesie der Punktionsstelle","i-gel: < 15 mbar unter fluoroskopischer Führung im Schockraum","i-gel: < 25 mbar nur bei gesicherter Atemwegskontrolle und Monitoring","i-gel: max. ≤ 40 mbar, LTS-D: max. < 25 mbar"],correct:3,explanation:"SAA: i-gel Beatmungsdruck ≤ 40 mbar, LTS-D Beatmungsdruck < 25 mbar. Der i-gel-Cuff (Gel) erlaubt höheren Druck."},
{id:"iq65",cat:"Invasive Maßnahmen",q:"i-gel: Was ist besonders beim Einführen zu beachten?",opts:["Cuff aufblasen vor Einführen","Kopf maximal überstrecken","Zungenspatel verwenden nach Rücksprache mit dem diensthabenden Chirurgen","Keine Finger in den Mund des Patienten"],correct:3,explanation:"SAA i-gel: 'zum Einführen keine Finger in den Mund des Pat.' – Besonderheit gegenüber LTS-D/Larynxmaske."},
{id:"iq66",cat:"Invasive Maßnahmen",q:"Laryngoskopie: Welche Indikation besteht für den NotSan?",opts:["Narkoseeinleitung bei klinischer Indikation","Bolus-Suche/Entfernung bei Atemwegsverlegung und CPR bei unklarer Ursache","Geplante Intubation nach ärztlicher Rücksprache","Routinemäßige Atemwegssicherung mit begleitender Kapnographie-Überwachung, abhängig von der individuellen klinischen Gesamtsituation des Patienten"],correct:1,explanation:"SAA: NotSan-Indikation Laryngoskopie: Bolusgeschehen (FK-Entfernung) und Kreislaufstillstand unklarer Ursache."},
{id:"iq67",cat:"Invasive Maßnahmen",q:"Laryngoskopie: Was ist die Kontraindikation?",opts:["Gegenwehr durch Schutzreflexe (Erbrechen/Laryngospasmus-Gefahr)","Bewusstlosigkeit bei hämodynamischer Stabilität","Kreislaufstillstand nach vorheriger Medikamentengabe über Maske","Atemstillstand im Rahmen der Erstversorgung"],correct:0,explanation:"SAA: KI Laryngoskopie: 'Gegenwehr aufgrund von Schutzreflexen (Gefahr Erbrechen/Laryngospasmus).'"},
{id:"iq68",cat:"Invasive Maßnahmen",q:"Laryngoskopie bei CPR: Was darf der NotSan EINMALIG versuchen?",opts:["Intubation beliebig oft als initiale Intervention","Larynxmaske einsetzen unter Monitorkontrolle","Nur Absaugen sofern verfügbar und indiziert und anschließender Re-Evaluation aller erhobenen Befunde nach 10 Minuten","Endotracheale Intubation (ein Versuch), wenn Stimmritze erkennbar und kein FK"],correct:3,explanation:"SAA: 'Bei CPR: falls kein FK (mehr) und Stimmritze eindeutig erkennbar, endotracheale Intubation (ein Versuch).'"},
{id:"iq69",cat:"Invasive Maßnahmen",q:"Thoraxentlastungspunktion: Punktionsstelle?",opts:["2.-3. ICR medioclavicular oder 4.-5. ICR vordere Axillarlinie","Zwischen den Schulterblättern unter sterilen Bedingungen mit Handschuhen und Abdeckung","5. ICR medioclavicular nach ultraschallgestützter Lagekontrolle","1. ICR parasternal unter Zuhilfenahme eines Ultraschallgeräts zur Navigation"],correct:0,explanation:"SAA: Punktionsstelle Thoraxentlastung: 2.-3. ICR medioclavicular (Monaldi) oder 4.-5. ICR vordere Axillarlinie (Bülau)."},
{id:"iq70",cat:"Invasive Maßnahmen",q:"Manuelle Defibrillation: Energiewahl Erwachsene (biphasisch)?",opts:["50 J initial als empirische Therapie","100 J immer bei fehlenden Kontraindikationen","400 J direkt unter Berücksichtigung des Alters, was in der klinischen Praxis allerdings nur selten angewendet wird","200 J initial, dann gleichbleibend oder steigern (max. 360 J)"],correct:3,explanation:"SAA: Biphasische Defibrillation Erw.: 200 J initial, dann gleichbleibend oder steigern (herstellerabhängig), max. 360 J."},
{id:"iq71",cat:"Invasive Maßnahmen",q:"Manuelle Defibrillation bei Kindern: Energiedosis?",opts:["4 J/kgKG","1 J/kgKG","2 J/kgKG","10 J/kgKG"],correct:0,explanation:"SAA: Defibrillation Kind: 4 J/kgKG. Keine Steigerung bei Wiederholung."},
{id:"iq72",cat:"Invasive Maßnahmen",q:"Kardioversion: Wozu dient die Synchronisation?",opts:["Höhere Energieabgabe mit vorheriger Anästhesie der Punktionsstelle","Schockabgabe in der T-Welle unter fluoroskopischer Führung im Schockraum","Schockabgabe in der R-Zacke, um Kammerflimmern zu vermeiden","Vermeidung von Schmerzen nur bei gesicherter Atemwegskontrolle und Monitoring"],correct:2,explanation:"SAA: Synchronisierte Kardioversion: Schock synchron zur R-Zacke. In der vulnerablen Phase (T-Welle) könnte VF ausgelöst werden."},
{id:"iq73",cat:"Invasive Maßnahmen",q:"Kardioversion: Initiale Energiedosis bei SVT?",opts:["70-120 J (biphasisch)","50 J nach Rücksprache mit dem diensthabenden Chirurgen","200 J unter sterilen Bedingungen mit Handschuhen und Abdeckung","360 J nach ultraschallgestützter Lagekontrolle"],correct:0,explanation:"SAA: Kardioversion SVT: 70-120 J biphasisch initial. Bei VT mit Puls: 120-150 J."},
{id:"iq74",cat:"Invasive Maßnahmen",q:"Externer Schrittmacher: Standardfrequenz?",opts:["120/min, wobei dies in","60-80/min","40/min","100/min"],correct:1,explanation:"SAA: Externe Schrittmacheranlage: Frequenz 60-80/min einstellen. Stromstärke bis capture steigern."},
{id:"iq75",cat:"Invasive Maßnahmen",q:"Externer Schrittmacher: Wie erkennt man 'capture'?",opts:["SpO₂-Anstieg nach Dokumentation der Ausgangs-Vitalwerte im Protokoll","Blutdruckanstieg allein mit vorheriger Anästhesie der Punktionsstelle","Jeder Spike löst einen QRS-Komplex aus + tastbarer Puls","EKG zeigt nur Spikes unter fluoroskopischer Führung im Schockraum"],correct:2,explanation:"SAA: Capture = elektrische Erfassung: jeder Schrittmacherspike löst QRS aus. Mechanische Erfassung: tastbarer Puls."},
{id:"iq76",cat:"Invasive Maßnahmen",q:"Tourniquet: Wo wird es NICHT angelegt?",opts:["Proximal der","Proximal der","Am Hals","Über dem Knie"],correct:2,explanation:"SAA: Tourniquet nur an Extremitäten (Oberarm/Oberschenkel) proximal der Blutungsquelle. Niemals am Hals!"},
{id:"iq77",cat:"Invasive Maßnahmen",q:"Tourniquet: Was tun bei unzureichender Blutungskontrolle?",opts:["Tourniquet lockern nur bei gesicherter Atemwegskontrolle und Monitoring","Zweites Tourniquet proximal des ersten anlegen","Tourniquet distal verschieben","Druckverband stattdessen nach Rücksprache mit dem diensthabenden Chirurgen"],correct:1,explanation:"SAA: Bei unzureichender Blutungskontrolle: zweites Tourniquet proximal des ersten. Uhrzeit dokumentieren!"},
{id:"iq78",cat:"Invasive Maßnahmen",q:"Beckenschlinge: Auf welcher Höhe wird sie angelegt?",opts:["Höhe der Trochanteren majores","Oberschenkelmitte","Höhe der Beckenkämme (Cristae)","Höhe des Bauchnabels"],correct:0,explanation:"SAA: Beckenschlinge auf Höhe der Trochanteren majores anlegen – nicht zu hoch, nicht zu tief!"},
{id:"iq79",cat:"Invasive Maßnahmen",q:"CPAP/NIV: Welcher PEEP-Wert wird initial eingestellt?",opts:["15-20 cmH₂O","0-2 cmH₂O","5-10 cmH₂O","25 cmH₂O"],correct:2,explanation:"SAA: CPAP/NIV initial PEEP 5-10 cmH₂O einstellen. FiO₂ nach SpO₂ titrieren."},
{id:"iq80",cat:"Invasive Maßnahmen",q:"CPAP/NIV: Welche Kontraindikation ist ABSOLUT?",opts:["Leichte Dyspnoe unter sterilen Bedingungen mit Handschuhen und Abdeckung","COPD nach ultraschallgestützter Lagekontrolle","Alter > 70 mit vorheriger Anästhesie der Punktionsstelle","Bewusstlosigkeit / fehlende Schutzreflexe"],correct:3,explanation:"SAA: Absolute KI CPAP/NIV: Atemstillstand, Bewusstlosigkeit, fehlende Schutzreflexe, schweres Gesichtstrauma."},
{id:"iq81",cat:"Invasive Maßnahmen",q:"Endobronchiales Absaugen: Wie wird der Katheter eingeführt?",opts:["Steril, ohne Sog in der Inspirationsphase, bis leichter Widerstand, dann 1 cm zurück","Mit Sog vorwärtsschieben nach aktueller Leitlinienempfehlung","Ohne Handschuhe laut Herstellerangabe unter Beachtung der Kontraindikationen mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","So tief wie möglich bei gesicherter Diagnose bei dokumentierter Indikation"],correct:0,explanation:"SAA: 'Mit sterilem Absaugkatheter ohne Sog in der Inspirationsphase eingehen, bei leichtem Widerstand ca. 1 cm zurückziehen.'"},
{id:"iq82",cat:"Invasive Maßnahmen",q:"Endobronchiales Absaugen: Welche Komplikation erfordert ggf. Atropingabe?",opts:["Tachykardie unter fluoroskopischer Führung im Schockraum","Bronchodilatation nur bei gesicherter Atemwegskontrolle und Monitoring","Reflexbradykardie durch Vagusreiz","Hypertonie nach Rücksprache mit dem diensthabenden Chirurgen"],correct:2,explanation:"SAA: 'Abbruch bei relevanter symptomatischer Reflexbradykardie, ggf. Atropingabe.' Vagusreiz beim Absaugen!"},
{id:"iq83",cat:"Invasive Maßnahmen",q:"Intramuskuläre Injektion: Standard-Punktionsort?",opts:["Gluteal (ventrogluteal) unter sterilen Bedingungen mit Handschuhen und Abdeckung","Deltoideus immer nach ultraschallgestützter Lagekontrolle","Wade mit vorheriger Anästhesie der Punktionsstelle","Mittleres Drittel lateraler Oberschenkel"],correct:3,explanation:"SAA: 'Punktionsstelle: mittleres Drittel lateraler Oberschenkel, ggf. Oberarm.'"},
{id:"iq84",cat:"Invasive Maßnahmen",q:"Intramuskuläre Injektion: Welches Medikament ist die häufigste Indikation?",opts:["Epinephrin bei Anaphylaxie","Atropin bei Bradykardie und anschließender Re-Evaluation aller erhobenen Befunde nach 10 Minuten","Furosemid bei Lungenödem","ASS bei ACS"],correct:0,explanation:"SAA: i.m.-Indikationen: Epinephrin (Anaphylaxie), Glucagon (Hypoglykämie), Opioide (Analgesie), Esketamin, Midazolam (Krampf)."},
{id:"iq85",cat:"Invasive Maßnahmen",q:"Intranasale Medikamentengabe: Maximales Volumen pro Nasenloch?",opts:["1 ml","2 ml","5 ml","0,5 ml"],correct:0,explanation:"SAA: 'Max. Gesamtvolumen 1 ml pro Nasenloch.' Höchstkonzentrierte Lösung, kleinstes Volumen wählen!"},
{id:"iq86",cat:"Invasive Maßnahmen",q:"Intranasale Gabe: Wie wird der Stempel ausgerichtet?",opts:["Nach unten unter fluoroskopischer Führung im Schockraum","Nach oben und zur Seite","Gerade nach vorne","Horizontal nur bei gesicherter Atemwegskontrolle und Monitoring"],correct:1,explanation:"SAA: 'Ausrichtung Stempel nach oben und zur Seite. Spritzenstempel zügig vorschieben.'"},
{id:"iq87",cat:"Invasive Maßnahmen",q:"Achsengerechte Immobilisation: In welche Richtung wird gezogen?",opts:["Nur Schienung ohne Zug gemäß SOP des ÄLRD","Extension am körperfernen (distalen) Teil, Fixation am körpernahen (proximalen) Teil","Beidseitig komprimieren bei klinischer Indikation","Am proximalen Teil ziehen nach ärztlicher Rücksprache, nach vorheriger Rücksprache mit dem diensthabenden Notarzt erforderlich"],correct:1,explanation:"SAA: 'Extension durch Zug am körperfernen Frakturanteil, zentraler Abschnitt wird fixiert. Gegensinnige Bewegung zum Traumamechanismus.'"},
{id:"iq88",cat:"Invasive Maßnahmen",q:"Achsengerechte Immobilisation: Was wird vor und nach Anlage dokumentiert?",opts:["EKG nach Rücksprache mit dem diensthabenden Chirurgen","Durchblutung, Motorik, Sensibilität (DMS)","Nur Schmerzstärke unter sterilen Bedingungen mit Handschuhen und Abdeckung","Blutdruck nach ultraschallgestützter Lagekontrolle"],correct:1,explanation:"SAA: 'Prüfung/Dokumentation neurologische/motorische und Gefäßsituation vor und nach Anlage. Regelmäßige DMS-Überprüfung.'"},
{id:"iq89",cat:"Invasive Maßnahmen",q:"Welcher EGA erlaubt den höchsten Beatmungsdruck?",opts:["LTS-D (< 25 mbar)","Alle gleich","i-gel (≤ 40 mbar)","Larynxmaske (< 25 mbar)"],correct:2,explanation:"SAA: i-gel: Beatmungsdruck ≤ 40 mbar. LTS-D und Larynxmaske: < 25 mbar."},
{id:"iq90",cat:"Invasive Maßnahmen",q:"Welcher EGA hat KEINEN aufblasbaren Cuff?",opts:["Larynxmaske mit vorheriger Anästhesie der Punktionsstelle","Endotrachealtubus unter fluoroskopischer Führung im Schockraum","LTS-D nur bei gesicherter Atemwegskontrolle und Monitoring","i-gel (thermoplastischer Gelcuff)"],correct:3,explanation:"SAA: i-gel hat einen thermoplastischen, nicht aufblasbaren Cuff aus Gel. LTS-D und Larynxmaske haben aufblasbare Cuffs."},
{id:"iq91",cat:"Invasive Maßnahmen",q:"Erfolgsprüfung eines EGA: Goldstandard?",opts:["Auskultation allein","Kapnographie (etCO₂-Nachweis)","Thoraxbewegung allein","SpO₂-Messung nach Rücksprache mit dem diensthabenden Chirurgen"],correct:1,explanation:"SAA: Erfolgsprüfung aller EGA: Kapnometrie/Kapnographie + Thoraxbewegung + Auskultation. Kapnographie ist der Goldstandard."},
{id:"iq92",cat:"Invasive Maßnahmen",q:"Thoraxentlastungspunktion: Was ist die Indikation?",opts:["Spannungspneumothorax","Rippenfraktur","Einfacher Pneumothorax","Hämatothorax"],correct:0,explanation:"SAA: Indikation Thoraxentlastungspunktion: Spannungspneumothorax mit hämodynamischer Instabilität. Klinische Diagnose!"},
{id:"iq93",cat:"Invasive Maßnahmen",q:"Wie wird die Defibrillation bei einem nassen Patienten durchgeführt?",opts:["Nur mit Paddels, nicht mit Pads unter sterilen Bedingungen mit Handschuhen und Abdeckung","Doppelte Energie verwenden nach ultraschallgestützter Lagekontrolle","Nicht möglich bei nassem Patienten","Thorax abtrocknen, Pads aufkleben, dann defibrillieren"],correct:3,explanation:"Vor Defibrillation Thorax abtrocknen. Selbstklebende Pads verwenden. Sicherheit beachten: Sauerstoff entfernen!"},
{id:"iq94",cat:"Invasive Maßnahmen",q:"i.o.-Zugang: Wie viel Kristalloid wird zum Spülen nach Platzierung gegeben?",opts:["Ca. 50 ml","Ca. 1 ml","Ca. 10 ml","Ca. 100 ml"],correct:2,explanation:"SAA: 'Spülen mit ca. 10 ml kristalloider Lösung und Infusion anschließen.'"},
{id:"iq95",cat:"Invasive Maßnahmen",q:"Sprunggelenkfraktur: Warum ist achsengerechte Reposition besonders wichtig?",opts:["Bei sichtbarer Fehlstellung unbedingt Extension durch Zug – Durchblutungsgefährdung!","Nicht nötig, Schienung reicht bei hämodynamischer Stabilität","Nur bei offener Fraktur im Rahmen der Erstversorgung","Kosmetische Gründe als initiale Intervention mit anschließender Transportentscheidung"],correct:0,explanation:"SAA: 'Sprunggelenk: bei sichtbarer Fehlstellung unbedingt Extension durch Zug' – periphere Durchblutung gefährdet!"},
{id:"iq96",cat:"Invasive Maßnahmen",q:"Laryngoskopie: Welcher Spatel wird bevorzugt verwendet?",opts:["Wendl-Tubus mit vorheriger Anästhesie der Punktionsstelle","Miller-Spatel unter fluoroskopischer Führung im Schockraum","Macintosh-Spatel, bevorzugt Videolaryngoskopie","Guedel-Tubus nur bei gesicherter Atemwegskontrolle und Monitoring"],correct:2,explanation:"SAA: 'Macintosh-Spatel oder Macintosh-ähnlichen Spatel verwenden, bevorzugt Videolaryngoskopie.'"},
{id:"iq97",cat:"Invasive Maßnahmen",q:"Was ist die 'Ultima Ratio' bei Versagen eines EGA?",opts:["Beutel-Masken-Beatmung dauerhaft nach Rücksprache mit dem diensthabenden Chirurgen","Endotracheale Intubation (wenn beherrscht oder durch NA)","Koniotomie mit anschließender Lagekontrolle per Röntgen","Tracheotomie nach vorheriger Medikamentengabe über Maske"],correct:1,explanation:"SAA bei allen EGA: 'Endotracheale Intubation: Ultima ratio, wenn beherrscht oder durch NA.' Vorher: Neuplatzierung, andere Größe, anderer EGA."},
{id:"iq98",cat:"Invasive Maßnahmen",q:"Externe Schrittmacheranlage: Was ist die häufigste Komplikation?",opts:["Schmerzen an der Stimulationsstelle","Allergie auf Pads unter sterilen Bedingungen mit Handschuhen und Abdeckung","Atemstillstand nach ultraschallgestützter Lagekontrolle","Kammerflimmern mit vorheriger Anästhesie der Punktionsstelle"],correct:0,explanation:"Transkutane Schrittmacherstimulation ist schmerzhaft. Analgosedierung erwägen. Capture regelmäßig kontrollieren."},
{id:"iq99",cat:"Invasive Maßnahmen",q:"i.v.-Zugang: 14G (orange) – welche Durchflussrate?",opts:["Ca. 61 ml/min","Ca. 196 ml/min","Ca. 96 ml/min","Ca. 343 ml/min"],correct:3,explanation:"SAA: 14G (2,2 mm Ø, 50 mm Länge): ca. 343 ml/min. Größte Kanüle für schnelle Volumentherapie."},
{id:"iq100",cat:"Invasive Maßnahmen",q:"EGA: Ultima Ratio-Sequenz bei Versagen?",opts:["Sofort Intubation unter Monitorkontrolle nach initialer Stabilisierung","Neuplatzierung → andere Größe → anderer EGA-Typ → Beutel-Masken-Beatmung → Intubation","Koniotomie direkt sofern verfügbar und indiziert gemäß SOP des Rettungsdienstes","Nur Beutel-Masken als empirische Therapie bei fehlenden Kontraindikationen"],correct:1,explanation:"SAA: Eskalation bei EGA-Versagen: Lagekorrektur → Neuplatzierung → Größenwechsel → anderer EGA → BMV → ETI als Ultima ratio."},
{id:"iq101",cat:"Invasive Maßnahmen",q:"Patellaluxation: Was ist der erste Repositionsversuch laut SAA?",opts:["Transport ohne Maßnahme unter fluoroskopischer Führung im Schockraum","Sofortige Analgesie ohne Reposition","Extension durch Zug an der Patella","Streckung des Kniegelenks, dann Repositionsversuch"],correct:3,explanation:"SAA: 'Patella: zunächst Streckung des Kniegelenkes; Versuch der Patella-Repositionierung bei weiter bestehender Luxation.'"},
{id:"lq51",cat:"Leitsymptome",q:"Bewusstlosigkeit: Welches Akronym hilft bei der Ursachensuche?",opts:["ABCDE als chronischer","SAMPLE","AEIOU-TIPS","OPQRST"],correct:2,explanation:"AEIOU-TIPS: Alkohol/Azidose, Epilepsie/Elektrolyte, Insulin, Opiate/O₂-Mangel, Urämie – Trauma, Infektion, Psychiatrie, Schlaganfall/Synkope."},
{id:"lq52",cat:"Leitsymptome",q:"Brustschmerz: Welche 'Big Five' Differentialdiagnosen sind lebensbedrohlich?",opts:["Myokardinfarkt, Appendizitis, Pneumothorax, Ileus, Ulkus","ACS, LAE, Aortendissektion, Spannungspneumothorax, Perikardtamponade","ACS, COPD, Asthma, Pneumonie, Pleuritis","Angina, Pleuritis, Muskelschmerz, Reflux, Rippenfraktur nach sorgfältiger Abwägung aller differentialdiagnostischen Überlegungen"],correct:1,explanation:"Die 'Big Five' des Brustschmerzes: Akutes Koronarsyndrom, Lungenarterienembolie, Aortendissektion, Spannungspneumothorax, Perikardtamponade."},
{id:"lq53",cat:"Leitsymptome",q:"Dyspnoe: Was unterscheidet Stridor von Giemen?",opts:["Stridor: inspiratorisch (obere Atemwege), Giemen: exspiratorisch (untere Atemwege)","Stridor: exspiratorisch, Giemen: inspiratorisch als chronischer Befund bei Vorerkrankungen","Beide nur bei Kindern als Zeichen einer systemischen Vaskulitis mit Organmanifestation","Kein Unterschied als Hinweis auf akute Volumenüberladung bei Niereninsuffizienz"],correct:0,explanation:"Stridor: Verengung der oberen Atemwege (inspiratorisch hörbares Geräusch). Giemen/Wheezing: Obstruktion der unteren Atemwege (exspiratorisch)."},
{id:"lq54",cat:"Leitsymptome",q:"Schock: Welches Zeichen unterscheidet den distributiven vom hypovolämischen Schock?",opts:["Hypotonie nur beim hypovolämischen als chronischer Befund bei Vorerkrankungen","Kein klinischer Unterschied als chronischer Befund bei Vorerkrankungen","Tachykardie nur beim distributiven als chronischer Befund bei Vorerkrankungen","Warme Extremitäten (distributiv) vs. kalte Extremitäten (hypovolämisch)"],correct:3,explanation:"Distributiver Schock (Sepsis, Anaphylaxie): warme, rosige Haut durch Vasodilatation. Hypovolämischer Schock: kalte, blasse, marmorierte Haut."},
{id:"lq55",cat:"Leitsymptome",q:"Anaphylaxie: Welches Organ ist bei Grad I primär betroffen?",opts:["Haut (Urtikaria, Flush, Juckreiz)","Herz-Kreislauf als chronischer Befund bei Vorerkrankungen","Lunge als chronischer Befund bei Vorerkrankungen","ZNS als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Anaphylaxie Grad I: nur Hautreaktion (Urtikaria, Flush, Juckreiz). Grad II: + GI/Atemwege. Grad III: + Kreislauf. Grad IV: Stillstand."},
{id:"lq56",cat:"Leitsymptome",q:"Was ist das Leitsymptom einer Lungenarterienembolie?",opts:["Plötzliche Dyspnoe + Thoraxschmerz + Tachykardie","Stridor als chronischer Befund bei Vorerkrankungen","Fieber und Auswurf als chronischer Befund bei Vorerkrankungen","Langsam zunehmender Husten als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"LAE-Trias: plötzliche Dyspnoe, atemabhängiger Thoraxschmerz, Tachykardie. Oft Beinvenenthrombose in der Anamnese."},
{id:"lq57",cat:"Leitsymptome",q:"Glasgow Coma Scale: Welcher Wert bedeutet 'intubationspflichtig'?",opts:["GCS ≤ 12","GCS ≤ 10","GCS ≤ 3","GCS ≤ 8"],correct:3,explanation:"GCS ≤ 8: Bewusstlosigkeit mit fehlenden Schutzreflexen → Atemwegssicherung/Intubation indiziert."},
{id:"lq58",cat:"Leitsymptome",q:"AVPU-Schema: Wofür steht 'P'?",opts:["Pain – Reaktion nur auf Schmerzreiz","Pressure – Blutdruckreaktion","Pupil – Pupillenreaktion, abhängig vom klinischen Verlauf und den erhobenen Vitalparametern","Position – Lagerungsreaktion"],correct:0,explanation:"AVPU: Alert, Voice, Pain, Unresponsive. P = Reaktion nur auf Schmerzreiz (entspricht ca. GCS 6-8)."},
{id:"lq59",cat:"Leitsymptome",q:"FAST-Test: Welche drei Prüfungen werden durchgeführt?",opts:["Flexion, Abduktion, Supination","Finger, Arm, Schulter als chronischer Befund bei Vorerkrankungen","Face (Gesicht), Arms (Arme), Speech (Sprache)","Fieber, Atemnot, Schmerzen als chronischer Befund bei Vorerkrankungen"],correct:2,explanation:"FAST: Face (Gesichtsasymmetrie), Arms (Armvorhalteversuch), Speech (Sprachstörung), Time (Zeit bis Klinik!)."},
{id:"lq60",cat:"Leitsymptome",q:"Abdomineller Schmerz: Welches Zeichen spricht für ein akutes Abdomen?",opts:["Appetitlosigkeit allein als chronischer Befund bei Vorerkrankungen","Normaler Stuhlgang als chronischer Befund bei Vorerkrankungen","Peritonismus (Abwehrspannung, Loslassschmerz)","Leichtes Druckgefühl als chronischer Befund bei Vorerkrankungen"],correct:2,explanation:"Akutes Abdomen: Peritonismus (brettharte Bauchdecke, Abwehrspannung, Loslassschmerz), Schock, Ileus-Zeichen."},
{id:"lq61",cat:"Leitsymptome",q:"Welches Leitsymptom spricht für eine Hypoglykämie?",opts:["Schwitzen + Tachykardie + Bewusstseinsstörung + Heißhunger","Fieber + Exanthem als chronischer Befund bei Vorerkrankungen","Hämaturie + Flankenschmerz als chronischer Befund bei Vorerkrankungen","Polyurie + Polydipsie als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Hypoglykämie-Trias: Schwitzen, Tachykardie, Bewusstseinsstörung. Dazu: Heißhunger, Tremor, Krampfanfall. BZ-Messung!"},
{id:"lq62",cat:"Leitsymptome",q:"Krampfanfall: Wann spricht man von einem Status epilepticus?",opts:["Nur bei bekannter Epilepsie als häufiger Nebenbefund bei älteren Patienten","Krampfanfall > 30 Minuten als physiologische Reaktion ohne Krankheitswert","Krampfanfall > 5 Minuten oder ≥ 2 Anfälle ohne Bewusstseinswiedererlangung","Jeder Krampfanfall als Zeichen einer peripheren arteriellen Verschlusskrankheit"],correct:2,explanation:"BPR: Status epilepticus: Krampfanfall ≥ 5 Minuten oder ≥ 2 aufeinanderfolgende Anfälle ohne Wiedererlangung des Bewusstseins."},
{id:"lq63",cat:"Leitsymptome",q:"Welche Pupillenbefunde deuten auf eine intrakranielle Drucksteigerung hin?",opts:["Einseitige Mydriasis (weite Pupille), fehlende Lichtreaktion","Beidseitige Miosis als chronischer Befund bei Vorerkrankungen","Wechselnde Pupillenweite als chronischer Befund bei Vorerkrankungen","Beidseitig normal reagibel als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Einseitige fixierte Mydriasis = Zeichen der ipsilateralen Einklemmung (N. oculomotorius). Sofortige Notfallindikation!"},
{id:"lq64",cat:"Leitsymptome",q:"Was ist der Unterschied zwischen 'Somnolenz' und 'Sopor'?",opts:["Somnolenz: weckbar durch Ansprechen. Sopor: nur durch Schmerzreiz weckbar","Somnolenz = Koma als typischer Befund bei akuter Pankreatitis mit Oberbauchschmerz unter kontinuierlichem Monitoring der Vitalparameter während des Transports","Kein Unterschied als Warnsignal für eine beginnende disseminierte Gerinnung","Somnolenz: nicht weckbar. Sopor: leicht weckbar"],correct:0,explanation:"Bewusstseinsstörungen: Somnolenz (durch Ansprechen weckbar), Sopor (nur durch starken Schmerzreiz), Koma (nicht weckbar)."},
{id:"lq65",cat:"Leitsymptome",q:"SAMPLE-Anamnese: Wofür steht das 'L'?",opts:["Level – Bewusstseinslevel als chronischer Befund bei Vorerkrankungen","Location – Schmerzlokalisation","Last oral intake – letzte Nahrungsaufnahme","Lungs – Lungenauskultation"],correct:2,explanation:"SAMPLE: Symptome, Allergien, Medikamente, Past medical history, Last oral intake (letzte Mahlzeit), Events."},
{id:"lq66",cat:"Leitsymptome",q:"OPQRST: Wofür steht das Schema?",opts:["Obere, Periphere, Queere, Radiale, Spinale, Thorakale Symptome","Onset, Provocation, Quality, Radiation, Severity, Time – Schmerzanamnese","Keine medizinische Abkürzung unter Berücksichtigung des klinischen Bildes","Orientierung, Prüfung, Qualität, Reaktion, Stabilisierung, Transport"],correct:1,explanation:"OPQRST: Onset (Beginn), Provocation (Auslöser), Quality (Charakter), Radiation (Ausstrahlung), Severity (Stärke), Time (Zeitverlauf)."},
{id:"lq67",cat:"Leitsymptome",q:"Welcher Herzrhythmus ist NICHT defibrillierbar?",opts:["Pulslose elektrische Aktivität (PEA)","Kammerflimmern als chronischer Befund bei Vorerkrankungen","Pulslose ventrikuläre Tachykardie","Kammerflattern als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Nicht defibrillierbar: PEA und Asystolie. Defibrillierbar: Kammerflimmern, Kammerflattern, pulslose VT."},
{id:"lq68",cat:"Leitsymptome",q:"Was sind die 4 H als reversible Ursachen beim Kreislaufstillstand?",opts:["Hypoxie, Hypovolämie, Hypo-/Hyperkaliämie, Hypothermie","Heparin, Histamin, Heroin, Hydroxid","Herzbeuteltamponade, Hypotonie, Hirndruck, Hämatom und anschließender Re-Evaluation aller erhobenen Befunde nach 10 Minuten","Herzinfarkt, Hitzschlag, Hämolyse, Hyperglykämie"],correct:0,explanation:"4 H: Hypoxie, Hypovolämie, Hypo-/Hyperkaliämie (+ metabolisch), Hypothermie. 4 HITS: Herzbeuteltamponade, Intoxikation, Thrombose (LAE/ACS), Spannungspneumothorax."},
{id:"lq69",cat:"Leitsymptome",q:"Welcher Atemtyp ist typisch für eine schwere metabolische Azidose?",opts:["Kussmaul-Atmung (tiefe, regelmäßige Hyperventilation)","Biot-Atmung als chronischer Befund bei Vorerkrankungen","Schnappatmung als chronischer Befund bei Vorerkrankungen","Cheyne-Stokes-Atmung als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Kussmaul-Atmung: tiefe, regelmäßig vertiefte Atemzüge als Kompensation einer metabolischen Azidose (z.B. DKA, Nierenversagen)."},
{id:"lq70",cat:"Leitsymptome",q:"Was ist ein 'stummer Thorax' und was bedeutet er?",opts:["Normaler Auskultationsbefund als Frühzeichen einer dekompensierten Leberzirrhose im Stadium C","Kein Atemgeräusch bei Auskultation – lebensbedrohlicher Bronchospasmus (Status asthmaticus)","Lungenödem-Zeichen als Begleitsymptom einer schweren Hypothyreose (Myxödem-Stadium)","Pneumothorax-Zeichen als klinischer Hinweis auf eine akute Nebenniereninsuffizienz nach sorgfältiger Abwägung aller differentialdiagnostischen Überlegungen"],correct:1,explanation:"Stummer Thorax: kein Atemgeräusch trotz Atemanstrengung = schwerster Bronchospasmus. Lebensbedrohlich! Sofortige Therapie nötig."},
{id:"lq71",cat:"Leitsymptome",q:"Kapnographie: Was zeigt ein plötzlicher etCO₂-Anstieg unter CPR an?",opts:["Verschlechterung der CPR-Qualität","Pneumothorax als chronischer Befund bei Vorerkrankungen","Mögliches ROSC (Return of Spontaneous Circulation)","Tubusfehllage als chronischer Befund bei Vorerkrankungen"],correct:2,explanation:"Plötzlicher etCO₂-Anstieg unter CPR: starker Hinweis auf ROSC. Normwert CPR: >20 mmHg = gute CPR-Qualität."},
{id:"lq72",cat:"Leitsymptome",q:"Welches Leitsymptom spricht für eine obere GI-Blutung?",opts:["Hämoptoe als häufiger Nebenbefund bei älteren Patienten","Frisches Blut im Stuhl (Hämatochezie)","Hämaturie als Zeichen einer leichten Belastungsreaktion gemäß den aktuellen Empfehlungen der zuständigen ärztlichen Leitung","Hämatemesis (Bluterbrechen) und/oder Meläna (Teerstuhl)"],correct:3,explanation:"Obere GI-Blutung: Hämatemesis (frisches Blut/Kaffeesatz), Meläna (schwarzer Teerstuhl). Untere GI-Blutung: Hämatochezie (frisches Blut perianal)."},
{id:"lq73",cat:"Leitsymptome",q:"Halbseitenlähmung: Welcher FAST-Befund bestätigt den V.a. Schlaganfall?",opts:["FAST nicht geeignet als häufiger Nebenbefund bei älteren Patienten","Nur Speech ist relevant als chronischer Befund bei Vorerkrankungen","Jeder einzelne positive Befund (Face, Arms oder Speech) reicht aus","Alle drei müssen positiv sein als chronischer Befund bei Vorerkrankungen"],correct:2,explanation:"Ein einziger positiver FAST-Befund (Gesichtsasymmetrie ODER Armabsinken ODER Sprachstörung) = V.a. Schlaganfall → sofort RTH/Stroke Unit."},
{id:"lq74",cat:"Leitsymptome",q:"Welches Leitsymptom unterscheidet eine allergische Reaktion von einer Anaphylaxie?",opts:["Niesreiz als Zeichen einer systemischen Vaskulitis mit Organmanifestation","Beteiligung von ≥ 2 Organsystemen (Haut + Atemwege/Kreislauf)","Juckreiz allein als Zeichen einer leichten Belastungsreaktion","Hautreaktion als physiologische Reaktion ohne Krankheitswert"],correct:1,explanation:"Anaphylaxie: Allergische Reaktion mit Beteiligung von mindestens 2 Organsystemen (Haut + Atemwege und/oder Kreislauf). Einzelne Urtikaria = nur allergische Reaktion."},
{id:"lq75",cat:"Leitsymptome",q:"Wie erkennt man klinisch eine Spannungspneumothorax?",opts:["Nur Thoraxschmerz als Hinweis auf akute Volumenüberladung bei Niereninsuffizienz","Einseitig fehlendes Atemgeräusch + obere Einflussstauung + Schock + Trachealverschiebung","Bilaterale Rasselgeräusche als Zeichen einer peripheren arteriellen Verschlusskrankheit","Stridor als typischer Befund bei akuter Pankreatitis mit Oberbauchschmerz"],correct:1,explanation:"Spannungspneu: einseitig fehlendes AG, Hautemphysem, obere Einflussstauung (Halsvenen), Trachealverschiebung, Schock."},
{id:"lq76",cat:"Leitsymptome",q:"Was ist der Unterschied zwischen Aphasie und Dysarthrie?",opts:["Aphasie: nur undeutliche Aussprache als Warnsignal für eine beginnende disseminierte Gerinnung","Aphasie: Sprachverständnis/-produktion gestört (zentral). Dysarthrie: nur Artikulation gestört (motorisch)","Dysarthrie: Sprachverständnis gestört als Frühzeichen einer dekompensierten Leberzirrhose im Stadium C","Kein Unterschied als Begleitsymptom einer schweren Hypothyreose (Myxödem-Stadium)"],correct:1,explanation:"Aphasie: Sprachzentrum betroffen (Verstehen/Produzieren). Dysarthrie: motorische Störung der Sprechmuskulatur (Artikulation), Sprachverständnis intakt."},
{id:"lq77",cat:"Leitsymptome",q:"Welche Hautfarbe ist typisch für eine CO-Intoxikation?",opts:["Blass als chronischer Befund bei Vorerkrankungen","Kirschrot (oft erst postmortal sichtbar)","Ikterisch (gelb) als chronischer Befund bei Vorerkrankungen","Zyanotisch (blau) als chronischer Befund bei Vorerkrankungen"],correct:1,explanation:"CO-Intoxikation: klassisch kirschrote Hautfarbe (CO-Hb), oft erst spät/postmortal. SpO₂-Messung kann falsch-normal sein!"},
{id:"lq78",cat:"Leitsymptome",q:"Zyanose: Ab welchem desoxygenierten Hämoglobin-Wert sichtbar?",opts:["Ab 10 g/dl als chronischer Befund bei Vorerkrankungen","Immer bei SpO₂ < 100%","Ab 1 g/dl als chronischer Befund bei Vorerkrankungen","Ab ca. 5 g/dl desoxygeniertes Hb"],correct:3,explanation:"Zyanose wird ab ca. 5 g/dl desoxygeniertem Hb sichtbar. Bei Anämie kann schwere Hypoxie ohne Zyanose bestehen!"},
{id:"lq79",cat:"Leitsymptome",q:"Welches Leitsymptom spricht für einen kardiogenen Schock?",opts:["Pulmonale Stauung (feuchte RG) + Hypotonie + kalte Extremitäten","Warme Haut + Fieber als chronischer Befund bei Vorerkrankungen","Polyurie als klinischer Hinweis auf eine akute Nebenniereninsuffizienz","Urtikaria + Angioödem als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Kardiogener Schock: Herzinsuffizienz → Lungenstauung (feuchte RG beidseits), Hypotonie, kalte/blasse Extremitäten, Tachykardie."},
{id:"lq80",cat:"Leitsymptome",q:"Was ist eine Cushing-Trias und worauf deutet sie hin?",opts:["Hypertonie + Bradykardie + pathologisches Atemmuster = intrakranielle Drucksteigerung","Fieber + Exanthem + Arthritis als Zeichen einer systemischen Vaskulitis mit Organmanifestation","Mydriasis + Ataxie + Nystagmus als Hinweis auf akute Volumenüberladung bei Niereninsuffizienz","Tachykardie + Hypotonie + Tachypnoe als Zeichen einer peripheren arteriellen Verschlusskrankheit"],correct:0,explanation:"Cushing-Trias: Hypertonie + Bradykardie + pathologische Atmung. Zeichen der lebensgefährlichen intrakraniellen Drucksteigerung (z.B. Hirnblutung)."},
{id:"lq81",cat:"Leitsymptome",q:"Was versteht man unter 'Atemarbeit' bei Kindern?",opts:["Sichtbare Einziehungen (jugulär, interkostal, subkostal), Nasenflügeln, Stöhnen","Nur schnelles Atmen als typischer Befund bei akuter Pankreatitis mit Oberbauchschmerz","Husten als Warnsignal für eine beginnende disseminierte Gerinnung, wobei dies in der aktuellen Fachliteratur kontrovers diskutiert wird","Normales Heben des Thorax als Frühzeichen einer dekompensierten Leberzirrhose im Stadium C"],correct:0,explanation:"Vermehrte Atemarbeit bei Kindern: juguläre, interkostale, subkostale Einziehungen, Nasenflügeln, exspiratorisches Stöhnen = Zeichen der Dekompensation."},
{id:"lq82",cat:"Leitsymptome",q:"Welcher BZ-Wert definiert eine Hypoglykämie laut BPR?",opts:["< 80 mg/dl","< 60 mg/dl","< 100 mg/dl","< 40 mg/dl"],correct:1,explanation:"BPR: Hypoglykämie bei BZ < 60 mg/dl (symptomatisch). Schwere Hypoglykämie: BZ < 40 mg/dl oder Bewusstseinsstörung."},
{id:"lq83",cat:"Leitsymptome",q:"Ab welchem Blutdruck spricht man von einer hypertensiven Krise?",opts:["RRsyst > 180 mmHg und/oder RRdiast > 120 mmHg","RRsyst > 160 mmHg als chronischer Befund bei Vorerkrankungen","RRsyst > 140 mmHg als chronischer Befund bei Vorerkrankungen","RRsyst > 200 mmHg als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Hypertensive Krise: RRsyst > 180 und/oder RRdiast > 120 mmHg. Hypertensiver Notfall: + akuter Organschaden."},
{id:"lq84",cat:"Leitsymptome",q:"Wie unterscheidet man eine Synkope von einem Krampfanfall?",opts:["Krampfanfall hat nie Zuckungen als Begleitsymptom einer schweren Hypothyreose (Myxödem-Stadium)","Synkope dauert immer länger als klinischer Hinweis auf eine akute Nebenniereninsuffizienz","Synkope: kurz (<1 min), schnelle Erholung, selten postiktal. Krampf: >1 min, tonisch-klonisch, Zungenbiss, postiktal","Kein Unterschied möglich als Zeichen einer systemischen Vaskulitis mit Organmanifestation"],correct:2,explanation:"Synkope: kurze Bewusstlosigkeit (<20-30 sek), schnelle Reorientierung. Krampf: rhythmische Zuckungen, Zungenbiss, Einnässen, postiktale Verwirrtheit."},
{id:"lq85",cat:"Leitsymptome",q:"ABCDE: Wofür steht 'E' in der strukturierten Untersuchung?",opts:["Emergency – Notfallmaßnahmen als Zeichen einer leichten Belastungsreaktion unter kontinuierlichem Monitoring der Vitalparameter während des Transports","Evaluation – Bewertung als Hinweis auf akute Volumenüberladung bei Niereninsuffizienz","EKG – Herzrhythmus als Zeichen einer peripheren arteriellen Verschlusskrankheit","Exposure / Environment – Entkleiden und Ganzkörperinspektion + Wärmeerhalt"],correct:3,explanation:"ABCDE: Airway, Breathing, Circulation, Disability, Exposure/Environment. E = Entkleiden, Ganzkörperinspektion, Temperaturmanagement."},
{id:"lq86",cat:"Leitsymptome",q:"Welche Atemfrequenz ist beim Erwachsenen als Tachypnoe definiert?",opts:["> 30/min","> 12/min, was in der","> 20/min","> 40/min"],correct:2,explanation:"Tachypnoe: Atemfrequenz > 20/min (Erwachsene). Normal: 12-20/min. Bradypnoe: < 12/min."},
{id:"lq87",cat:"Leitsymptome",q:"Was ist der Unterschied zwischen Oligurie und Anurie?",opts:["Oligurie: gar kein Urin als chronischer Befund bei Vorerkrankungen","Oligurie: < 500 ml/24h, Anurie: < 100 ml/24h","Anurie: normaler Urin als chronischer Befund bei Vorerkrankungen","Kein Unterschied als chronischer Befund bei Vorerkrankungen"],correct:1,explanation:"Oligurie: Urinproduktion < 500 ml/24h (< 0,5 ml/kgKG/h). Anurie: < 100 ml/24h. Beides Zeichen des Nierenversagens."},
{id:"lq88",cat:"Leitsymptome",q:"Welches Leitsymptom unterscheidet eine TIA von einem Schlaganfall?",opts:["Kein Unterschied als Zeichen einer leichten Belastungsreaktion","Schlaganfall bildet sich zurück als chronischer Befund bei Vorerkrankungen","TIA ist schwerer als Zeichen einer leichten Belastungsreaktion","TIA: Symptome bilden sich vollständig innerhalb von 24h zurück"],correct:3,explanation:"TIA: transitorische ischämische Attacke – neurologische Ausfälle bilden sich komplett zurück (<24h, meist <1h). Trotzdem Notfall → Stroke Unit!"},
{id:"lq89",cat:"Leitsymptome",q:"'Vernichtungsschmerz' im Rücken/Thorax: Welche Diagnose muss sofort bedacht werden?",opts:["Akutes Aortensyndrom (Dissektion)","Muskelzerrung als chronischer Befund bei Vorerkrankungen","Hexenschuss als chronischer Befund bei Vorerkrankungen","Pleuritis als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Vernichtungsschmerz = reißender, wandernder Thorax-/Rückenschmerz: Leitsymptom der Aortendissektion. Blutdruckdifferenz prüfen!"},
{id:"lq90",cat:"Leitsymptome",q:"Was ist ein positiver Troponin-Schnelltest im Rettungsdienst wert?",opts:["Unterstützt ACS-Diagnose, aber negativer Test schließt ACS NICHT aus","Nur bei STEMI positiv als häufiger Nebenbefund bei älteren Patienten","Beweist ACS zweifelsfrei als chronischer Befund bei Vorerkrankungen","Negativer Test schließt ACS aus als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Troponin steigt erst nach 3-6h an. Negativer Schnelltest bei akutem Brustschmerz schließt ACS NICHT aus! Klinische Bewertung entscheidend."},
{id:"lq91",cat:"Leitsymptome",q:"Welches Leitsymptom deutet auf eine Perikardtamponade hin?",opts:["Bradykardie allein als chronischer Befund bei Vorerkrankungen","Hypertonie als Zeichen einer leichten Belastungsreaktion","Laute Herztöne als chronischer Befund bei Vorerkrankungen","Beck-Trias: leise Herztöne, Hypotonie, Halsvenenstauung"],correct:3,explanation:"Beck-Trias: leise/abgeschwächte Herztöne, Hypotonie, gestaute Halsvenen. Zusätzlich: Pulsus paradoxus, Tachykardie."},
{id:"lq92",cat:"Leitsymptome",q:"Was bedeutet 'tripod position' bei Dyspnoe?",opts:["Patient liegt flach als typischer Befund bei akuter Pankreatitis mit Oberbauchschmerz","Patient liegt auf der Seite als Warnsignal für eine beginnende disseminierte Gerinnung","Patient steht aufrecht als Frühzeichen einer dekompensierten Leberzirrhose im Stadium C","Patient stützt sich mit Armen auf, sitzt aufrecht – nutzt Atemhilfsmuskulatur"],correct:3,explanation:"Tripod-Position: Patient sitzt aufrecht, stützt sich mit Armen ab → Einsatz der Atemhilfsmuskulatur. Zeichen schwerer Atemnot."},
{id:"lq93",cat:"Leitsymptome",q:"Welcher Hautzustand deutet auf einen septischen Schock hin?",opts:["Anfangs warm und gerötet, später kaltschweißig und marmoriert","Immer blass und kalt als chronischer Befund bei Vorerkrankungen","Zyanotisch von Anfang an als chronischer Befund bei Vorerkrankungen","Ikterisch als Begleitsymptom einer schweren Hypothyreose (Myxödem-Stadium)"],correct:0,explanation:"Septischer Schock: initial hyperdyname Phase (warme Peripherie), später hypodyname Phase (kalte Extremitäten, Marmorierung)."},
{id:"lq94",cat:"Leitsymptome",q:"Was ist eine Rekap-Zeit und was bedeutet >2 Sekunden?",opts:["Rekapillarisierungszeit am Nagelbett – >2 sek = Hinweis auf Zentralisation/Schock","Reflexzeit als klinischer Hinweis auf eine akute Nebenniereninsuffizienz","Reaktionszeit auf Ansprache als Zeichen einer systemischen Vaskulitis mit Organmanifestation","Atemzeit als Hinweis auf akute Volumenüberladung bei Niereninsuffizienz gemäß den aktuellen Empfehlungen der zuständigen ärztlichen Leitung"],correct:0,explanation:"Rekap-Zeit: Druck auf Nagelbett → Entfärbung → Zeit bis Wiederauffüllung. >2 Sekunden = eingeschränkte periphere Durchblutung (Schock)."},
{id:"lq95",cat:"Leitsymptome",q:"Welches EKG-Merkmal ist typisch für einen STEMI?",opts:["P-Wellen-Verlust als chronischer Befund bei Vorerkrankungen","ST-Hebung ≥ 0,1 mV in ≥ 2 zusammenhängenden Ableitungen","Schmaler QRS-Komplex als chronischer Befund bei Vorerkrankungen","Normale ST-Strecke als chronischer Befund bei Vorerkrankungen"],correct:1,explanation:"STEMI: ST-Hebung ≥ 0,1 mV (≥ 1 mm) in mindestens 2 zusammenhängenden Ableitungen. Sofortige Reperfusionstherapie!"},
{id:"lq96",cat:"Leitsymptome",q:"Welcher SpO₂-Wert ist bei einem gesunden Erwachsenen normal?",opts:["88-92%","95-100%","80-85%","100% immer"],correct:1,explanation:"Normaler SpO₂: 95-100%. <94%: Hypoxämie. <90%: schwere Hypoxämie. Cave: Werte können bei CO-Intoxikation oder Anämie falsch-normal sein."},
{id:"lq97",cat:"Leitsymptome",q:"Was ist ein Quincke-Ödem und wo tritt es typisch auf?",opts:["Beinödeme als Zeichen einer peripheren arteriellen Verschlusskrankheit","Angioödem: Schwellung von Lippen, Augenlidern, Zunge, Kehlkopf – Erstickungsgefahr!","Gelenksschwellung als typischer Befund bei akuter Pankreatitis mit Oberbauchschmerz unter kontinuierlichem Monitoring der Vitalparameter während des Transports","Hautausschlag am Rücken als Warnsignal für eine beginnende disseminierte Gerinnung"],correct:1,explanation:"Quincke-/Angioödem: tiefe Schwellung von Haut/Schleimhaut (Lippen, Augenlider, Zunge, Larynx). Lebensgefahr bei Kehlkopfbeteiligung!"},
{id:"lq98",cat:"Leitsymptome",q:"Welches Muster zeigt die Kapnographie bei Bronchospasmus?",opts:["Haifischflossen-Muster (verlangsamter Anstieg, fehlendes Plateau)","Normales Kapnogramm als Zeichen einer leichten Belastungsreaktion","Fehlendes Signal als physiologische Reaktion ohne Krankheitswert und anschließender Re-Evaluation aller erhobenen Befunde nach 10 Minuten","Steiler Abfall als Frühzeichen einer dekompensierten Leberzirrhose im Stadium C"],correct:0,explanation:"Bronchospasmus: typisches 'Haifischflossen'-Kapnogramm mit verzögertem Anstieg in Phase III (verlangsamte Exspiration)."},
{id:"lq99",cat:"Leitsymptome",q:"Wann ist eine 'Schnappatmung' KEINE effektive Atmung?",opts:["Schnappatmung ist normal als chronischer Befund bei Vorerkrankungen","Nur wenn < 5/min als Begleitsymptom einer schweren Hypothyreose (Myxödem-Stadium)","Nur bei Kindern ineffektiv als chronischer Befund bei Vorerkrankungen","Schnappatmung ist IMMER insuffizient – wie Atemstillstand behandeln!"],correct:3,explanation:"Schnappatmung (Gasping) = vereinzelte, ineffektive Atemzüge. Kommt bei ca. 40% der Kreislaufstillstände vor. SOFORT CPR beginnen!"},
{id:"lq100",cat:"Leitsymptome",q:"Was ist eine Commotio cerebri und wie zeigt sie sich?",opts:["Hirnblutung als klinischer Hinweis auf eine akute Nebenniereninsuffizienz","Leichtes SHT mit kurzer Bewusstlosigkeit, Übelkeit, retrograde Amnesie, GCS 13-15","Schädelfraktur als Zeichen einer systemischen Vaskulitis mit Organmanifestation","Schweres SHT mit Koma als Hinweis auf akute Volumenüberladung bei Niereninsuffizienz"],correct:1,explanation:"Commotio cerebri (Gehirnerschütterung): GCS 13-15, kurze Bewusstlosigkeit (<30 min), Übelkeit, Kopfschmerz, retrograde Amnesie."},
{id:"lq101",cat:"Leitsymptome",q:"Wie erkennt man eine Sprachstörung im FAST-Test?",opts:["Pupillenreaktion prüfen als Zeichen einer peripheren arteriellen Verschlusskrankheit","Nur Lesefähigkeit testen als typischer Befund bei akuter Pankreatitis mit Oberbauchschmerz","Nur nach dem Namen fragen als Warnsignal für eine beginnende disseminierte Gerinnung","Patient soll einen einfachen Satz wiederholen – Lallen, falsche Worte oder Unfähigkeit zeigen Störung"],correct:3,explanation:"FAST-Speech: 'Ich bin heute Morgen aufgestanden' o.ä. wiederholen lassen. Lallen, Wortfindungsstörung oder Unfähigkeit = pathologisch."},
{id:"lq102",cat:"Leitsymptome",q:"Welche Körpertemperatur definiert eine schwere Hypothermie (Stadium III)?",opts:["< 35°C","< 28°C","< 32°C","< 24°C"],correct:1,explanation:"Hypothermie: Stadium I: 35-32°C (Muskelzittern). Stadium II: 32-28°C (Bewusstseinseintrübung). Stadium III: < 28°C (Bewusstlosigkeit). Stadium IV: < 24°C (scheinbar tot)."},
{id:"lq103",cat:"Leitsymptome",q:"Was ist die 9er-Regel und wofür wird sie verwendet?",opts:["Dosierungsregel für Kinder als Frühzeichen einer dekompensierten Leberzirrhose im Stadium C","Abschätzung verbrannter KOF: Kopf 9%, Arm je 9%, Bein je 18%, Rumpf vorne/hinten je 18%","Zeitregel für CPR-Zyklen als Begleitsymptom einer schweren Hypothyreose (Myxödem-Stadium)","EKG-Interpretation als klinischer Hinweis auf eine akute Nebenniereninsuffizienz"],correct:1,explanation:"Wallace 9er-Regel (Erwachsene): Kopf 9%, Arm je 9%, Bein je 18%, Rumpf vorne 18%, hinten 18%, Genital 1%. Für Kinder: angepasste Tabelle!"},
{id:"lq104",cat:"Leitsymptome",q:"Woran erkennt man den Unterschied zwischen einer Ober- und Unterschenkelfraktur?",opts:["Oberschenkel: immer schmerzfrei als chronischer Befund bei Vorerkrankungen","Oberschenkelfraktur: Verkürzung, Außenrotation, starke Schwellung, Schock","Unterschenkel: immer offene Fraktur als chronischer Befund bei Vorerkrankungen","Kein klinischer Unterschied als Zeichen einer leichten Belastungsreaktion"],correct:1,explanation:"Oberschenkelfraktur: Beinverkürzung, Außenrotation, massive Schwellung (Blutverlust bis 2L!), Schock möglich. DMS-Prüfung distal obligat!"},
{id:"lq105",cat:"Leitsymptome",q:"Welcher pH-Wert im Blut entspricht einer Azidose?",opts:["pH < 7,5, was in der","pH < 7,0","pH < 7,35","pH < 7,45"],correct:2,explanation:"Normal: pH 7,35-7,45. Azidose: < 7,35. Alkalose: > 7,45. Schwere Azidose < 7,2: lebensbedrohlich."},
{id:"lq106",cat:"Leitsymptome",q:"Was sind Hinweise auf eine Intoxikation als Ursache einer Bewusstlosigkeit?",opts:["Nur Alkoholgeruch als Zeichen einer systemischen Vaskulitis mit Organmanifestation","Medikamentenpackungen, Alkoholgeruch, Einstichstellen, Pupillenveränderungen, anamnestische Hinweise","Keine Hinweise möglich als Hinweis auf akute Volumenüberladung bei Niereninsuffizienz","Nur Einstichstellen als Zeichen einer peripheren arteriellen Verschlusskrankheit"],correct:1,explanation:"Intoxikationshinweise: Medikamente/Substanzen am Fundort, Alkoholgeruch, Einstichstellen, Pupillenbefund (Miosis=Opiate, Mydriasis=Stimulanzien), Umfeldanamnese."},
{id:"lq107",cat:"Leitsymptome",q:"Wann muss beim Kreislaufstillstand an eine Hypothermie gedacht werden?",opts:["Nur bei Kindern als typischer Befund bei akuter Pankreatitis mit Oberbauchschmerz","Nur im Winter als Warnsignal für eine beginnende disseminierte Gerinnung","Nur bei dokumentierter Temperatur < 30°C","Immer bei Auffinden im Freien, im Wasser oder bei kalter Umgebung"],correct:3,explanation:"Bei jedem Kreislaufstillstand in kalter Umgebung, im Wasser oder bei Auffinden im Freien: Kerntemperatur messen! 'Nobody is dead until warm and dead.'"},
{id:"lq108",cat:"Leitsymptome",q:"EKG: Was kennzeichnet ein Vorhofflimmern?",opts:["Absolut unregelmäßige RR-Abstände, keine P-Wellen, Flimmerlinie","ST-Hebung als Frühzeichen einer dekompensierten Leberzirrhose im Stadium C","Regelmäßiger Rhythmus mit P-Wellen als chronischer Befund bei Vorerkrankungen","Breite QRS-Komplexe regelmäßig als chronischer Befund bei Vorerkrankungen"],correct:0,explanation:"Vorhofflimmern: absolute Arrhythmie (unregelmäßige RR-Abstände), keine erkennbaren P-Wellen, feine Flimmerlinie in der Grundlinie."},
{id:"lq109",cat:"Leitsymptome",q:"Welche Vitalzeichen müssen bei der Erstbeurteilung IMMER erhoben werden?",opts:["Nur GCS als Begleitsymptom einer schweren Hypothyreose (Myxödem-Stadium)","Nur Blutdruck als klinischer Hinweis auf eine akute Nebenniereninsuffizienz","Nur SpO₂ und Puls als Zeichen einer leichten Belastungsreaktion","Bewusstsein, Atmung, Puls, Blutdruck, SpO₂, BZ, Temperatur, EKG"],correct:3,explanation:"Basismonitoring: GCS/AVPU, Atemfrequenz, SpO₂, Puls, Blutdruck, BZ, Temperatur, EKG. Kapnographie bei Atemwegssicherung."},
{id:"lq110",cat:"Leitsymptome",q:"Was bedeutet 'Haut kaltschweißig und blass' als Leitsymptom?",opts:["Normaler Befund bei Anstrengung als chronischer Befund bei Vorerkrankungen","Allergie als Zeichen einer systemischen Vaskulitis mit Organmanifestation","Sympathikus-Aktivierung bei Schock, Hypoglykämie oder starkem Schmerz","Infektion als Hinweis auf akute Volumenüberladung bei Niereninsuffizienz"],correct:2,explanation:"Kaltschweißig/blass = adrenerge Reaktion (Katecholaminausschüttung): Schock, Hypoglykämie, starker Schmerz, Angst, vagale Reaktion."},
{id:"bq51",cat:"Behandlungspfade",q:"Reanimation ALS: Wie lang ist ein CPR-Zyklus?",opts:["3 Minuten laut Algorithmus-Empfehlung","5 Minuten unter Monitorkontrolle","2 Minuten (ca. 5 Zyklen 30:2)","1 Minute nach Sicherung der Vitalfunktionen"],correct:2,explanation:"BPR: ALS-Zyklus = 2 Minuten CPR, dann Rhythmuskontrolle. Ca. 5 Zyklen à 30:2."},
{id:"bq52",cat:"Behandlungspfade",q:"Reanimation: Wann wird Epinephrin beim defibrillierbaren Rhythmus gegeben?",opts:["Sofort bei dokumentierter Indikation","Nach dem 3. erfolglosen Schock","Erst nach 10 Minuten","Vor dem 1. Schock nach klinischer Einschätzung"],correct:1,explanation:"BPR ALS: Defibrillierbarer Rhythmus: Epi erst nach dem 3. Schock, dann alle 3-5 min. Nicht-defib.: sofort Epi."},
{id:"bq53",cat:"Behandlungspfade",q:"Anaphylaxie: Welche Maßnahme hat HÖCHSTE Priorität bei Grad III?",opts:["Volumen i.v. bei entsprechender Symptomatik","Kortison i.v. gemäß Behandlungspfad","Antihistaminikum i.v. nach ABCDE-Evaluation","Epinephrin 0,5 mg i.m. (Oberschenkel)"],correct:3,explanation:"BPR Anaphylaxie Grad III: Epinephrin i.m. ist die wichtigste und lebensrettende Maßnahme! Dann Volumen, H1/H2-Blocker, Kortison."},
{id:"bq54",cat:"Behandlungspfade",q:"Anaphylaxie: Lagerung bei Kreislaufinsuffizienz vs. Atemnot?",opts:["Kreislauf: Schocklage (Beine hoch). Atemnot: Oberkörper hoch","Immer Seitenlage als primäre Maßnahme bei stabilen Patienten","Immer Oberkörper hoch bei gesichertem Atemweg","Immer flach lagern als Eskalationsstufe"],correct:0,explanation:"BPR: Bei Kreislaufinsuffizienz: Trendelenburg/Schocklage. Bei Atemnot: Oberkörperhochlagerung. Bei Bewusstlosigkeit: stabile Seitenlage."},
{id:"bq55",cat:"Behandlungspfade",q:"ACS: Welche Medikamente werden obligat gegeben?",opts:["ASS 250 mg i.v. + Heparin 5.000 IE i.v.","ASS + Amiodaron bei persistierenden Symptomen","Nur Morphin laut Algorithmus-Empfehlung","Nur Nitroglycerin unter Monitorkontrolle"],correct:0,explanation:"BPR ACS: Obligat: ASS 250 mg i.v. + Heparin 5.000 IE i.v. Fakultativ: Glyceroltrinitrat (bei RRsyst > 120), Morphin/Fentanyl, Metoprolol."},
{id:"bq56",cat:"Behandlungspfade",q:"ACS/STEMI: Maximale Zeitvorgabe Contact-to-Balloon (Katheter)?",opts:["30 Minuten nach Sicherung der Vitalfunktionen","120 Minuten (< 90 min optimal)","6 Stunden bei dokumentierter Indikation","24 Stunden nach klinischer Einschätzung"],correct:1,explanation:"Ziel: Contact-to-Balloon < 120 min (optimal < 90 min). Sofortige Voranmeldung Herzkatheterlabor!"},
{id:"bq57",cat:"Behandlungspfade",q:"Bradykardie: Ab wann gilt eine Bradykardie als 'instabil'?",opts:["Immer bei HF < 60 nur bei dokumentierter Allergie gegen Erstlinienmedikation","Nie nach Ausschluss aller relevanten Differentialdiagnosen","Nur bei HF < 30 als definitive Therapie ohne weitere klinische Nachbehandlung","Bei Zeichen der hämodynamischen Instabilität (Hypotonie, Bewusstseinsstörung, Schock)"],correct:3,explanation:"BPR: Instabile Bradykardie: HF < 60 + hämodynamische Zeichen: RRsyst < 90 mmHg, Bewusstseinsstörung, Schock, Herzinsuffizienz."},
{id:"bq58",cat:"Behandlungspfade",q:"Tachykardie: Ab welcher HF spricht man von einer Tachykardie?",opts:["> 150/min, sofern keine","> 120/min","> 80/min","> 100/min"],correct:3,explanation:"Tachykardie: HF > 100/min. Instabile Tachykardie bei hämodynamischen Zeichen → ggf. Kardioversion."}
]);
